Do you know music fx dj by Google labs? It uses the google lyria realtime model. Can you remake it full replica? (With lyria, yes.)

You CAN use lyria as an api.

import { GoogleGenAI } from "@google/genai";
import Speaker from "speaker";
import { Buffer } from "buffer";

const client = new GoogleGenAI({
apiKey: GEMINI_API_KEY,
apiVersion: "v1alpha" ,
});

async function main() {
const speaker = new Speaker({
channels: 2,       // stereo
bitDepth: 16,      // 16-bit PCM
sampleRate: 44100, // 44.1 kHz
});

const session = await client.live.music.connect({
model: "models/lyria-realtime-exp",
callbacks: {
onmessage: (message) => {
if (message.serverContent?.audioChunks) {
for (const chunk of message.serverContent.audioChunks) {
const audioBuffer = Buffer.from(chunk.data, "base64");
speaker.write(audioBuffer);
}
}
},
onerror: (error) => console.error("music session error:", error),
onclose: () => console.log("Lyria RealTime stream closed."),
},
});

await session.setWeightedPrompts({
weightedPrompts: [
{ text: "Minimal techno with deep bass, sparse percussion, and atmospheric synths", weight: 1.0 },
],
});

await session.setMusicGenerationConfig({
musicGenerationConfig: {
bpm: 90,
temperature: 1.0,
audioFormat: "pcm16",  // important so we know format
sampleRateHz: 44100,
},
});

await session.play();
}

main().catch(console.error);

It's right there in https://ai.google.dev/gemini-api/docs/music-generation

I have added the UI example attachment

