{
  "name": "MusicFX DJ Replica",
  "description": "A replica of Google Labs MusicFX DJ using the Gemini Lyria Realtime API for generative music."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface WeightedPrompt {
  id: string;
  text: string;
  weight: number;
  color: string; // Hex color for the UI slider
  isActive: boolean;
}

export interface MusicGenerationConfig {
  bpm: number;
  temperature: number;
  audioFormat: string;
  sampleRateHz: number;
}

// Defining the shape of the experimental Lyria API based on user request
export interface LyriaSession {
  setWeightedPrompts: (args: { weightedPrompts: { text: string; weight: number }[] }) => Promise<void>;
  setMusicGenerationConfig: (args: { musicGenerationConfig: MusicGenerationConfig }) => Promise<void>;
  play: () => Promise<void>;
  pause: () => Promise<void>; // Assuming pause exists or we close connection
  close: () => Promise<void>;
}

export type MacroLevel = 'low' | 'med' | 'high';

export interface MacroState {
  density: MacroLevel;
  brightness: MacroLevel;
  chaos: MacroLevel;
}

export interface InstrumentState {
  drums: boolean;
  bass: boolean;
  other: boolean;
}

// In a real production app, this should be fetched securely.
// For this demo, we assume process.env.API_KEY is available.
export const API_KEY = process.env.API_KEY || '';

export const SAMPLE_RATE = 44100;

export const DEFAULT_PROMPTS = [
  { id: '1', text: 'cello punk song', weight: 0.8, color: '#4fd1c5', isActive: true },
  { id: '2', text: 'g-funk', weight: 0.6, color: '#9dffc0', isActive: true },
  { id: '3', text: 'nature sounds', weight: 0.3, color: '#f6e05e', isActive: true },
];

export const SUGGESTIONS = [
  'afrobeat', 'grime symphony', 'existential angst', 'disco funk', 
  'industrial rock', 'underwater dj', 'pipa', 'lo-fi beats'
];

import { GoogleGenAI } from "@google/genai";
import { API_KEY, SAMPLE_RATE } from "../constants";
import { LyriaSession, MusicGenerationConfig, WeightedPrompt } from "../types";

class MusicService {
  private client: GoogleGenAI;
  private session: LyriaSession | null = null;
  private audioContext: AudioContext | null = null;
  private nextStartTime: number = 0;
  private analyser: AnalyserNode | null = null;
  private gainNode: GainNode | null = null;
  private isConnected: boolean = false;

  constructor() {
    this.client = new GoogleGenAI({
      apiKey: API_KEY,
      apiVersion: "v1alpha", // As requested
    });
  }

  // Initialize Audio Context (must be called after user interaction)
  private initAudioContext() {
    if (!this.audioContext) {
      this.audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({
        sampleRate: SAMPLE_RATE,
      });
      this.analyser = this.audioContext.createAnalyser();
      this.analyser.fftSize = 256;
      this.gainNode = this.audioContext.createGain();

      // Connect graph: Source -> Gain -> Analyser -> Destination
      this.gainNode.connect(this.analyser);
      this.analyser.connect(this.audioContext.destination);
    }
  }

  public getAnalyser(): AnalyserNode | null {
    return this.analyser;
  }

  public async connect(): Promise<void> {
    if (this.isConnected) return;
    this.initAudioContext();

    try {
      // NOTE: We are casting to 'any' here because 'live.music' is an experimental 
      // API surface not yet in the public types definition of the standard SDK, 
      // but requested explicitly by the user.
      const musicClient = (this.client as any).live?.music;

      if (!musicClient) {
        throw new Error("Music capability not found on GoogleGenAI client. Ensure you are using the correct experimental SDK version.");
      }

      console.log("Connecting to Lyria model...");

      this.session = await musicClient.connect({
        model: "models/lyria-realtime-exp",
        callbacks: {
          onmessage: (message: any) => {
            if (message.serverContent?.audioChunks) {
              for (const chunk of message.serverContent.audioChunks) {
                 this.scheduleAudioChunk(chunk.data);
              }
            }
          },
          onerror: (error: any) => console.error("Music session error:", error),
          onclose: () => {
            console.log("Lyria RealTime stream closed.");
            this.isConnected = false;
          },
        },
      });

      this.isConnected = true;
      console.log("Connected to Lyria.");
    } catch (e) {
      console.error("Failed to connect:", e);
      throw e;
    }
  }

  private base64ToArrayBuffer(base64: string): ArrayBuffer {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes.buffer;
  }

  private scheduleAudioChunk(base64Data: string) {
    if (!this.audioContext || !this.gainNode) return;

    // 1. Decode Base64 to ArrayBuffer
    const rawBuffer = this.base64ToArrayBuffer(base64Data);

    // 2. Convert PCM16 (Int16) to Float32
    // The model returns raw PCM16 samples.
    const int16Data = new Int16Array(rawBuffer);
    const float32Data = new Float32Array(int16Data.length);

    for (let i = 0; i < int16Data.length; i++) {
      // Normalize to -1.0 to 1.0
      float32Data[i] = int16Data[i] / 32768.0;
    }

    // 3. Create AudioBuffer
    const audioBuffer = this.audioContext.createBuffer(
      1, // Assuming mono for this chunk, or 2 if interleaved. The user sample said channels: 2.
         // If interleaved, we need to split. Let's assume the API returns standard interleaved stereo.
      int16Data.length / 2, 
      SAMPLE_RATE
    );

    // De-interleave if stereo
    const leftChannel = audioBuffer.getChannelData(0);
    const rightChannel = audioBuffer.getChannelData(1);

    for (let i = 0; i < audioBuffer.length; i++) {
        leftChannel[i] = float32Data[i * 2];
        rightChannel[i] = float32Data[i * 2 + 1];
    }

    // 4. Schedule Playback
    const source = this.audioContext.createBufferSource();
    source.buffer = audioBuffer;
    source.connect(this.gainNode);

    // Ensure play scheduling is gapless
    const currentTime = this.audioContext.currentTime;
    if (this.nextStartTime < currentTime) {
      this.nextStartTime = currentTime;
    }

    source.start(this.nextStartTime);
    this.nextStartTime += audioBuffer.duration;
  }

  public async play() {
    if (!this.session) await this.connect();
    if (this.audioContext?.state === 'suspended') {
      await this.audioContext.resume();
    }
    await this.session?.play();
  }

  public async setPrompts(prompts: WeightedPrompt[]) {
    if (!this.session) return;

    const apiPrompts = prompts
      .filter(p => p.isActive)
      .map(p => ({
        text: p.text,
        weight: p.weight
      }));

    // If no prompts are active, send a silence prompt or keep connection open
    if (apiPrompts.length === 0) return;

    await this.session.setWeightedPrompts({
      weightedPrompts: apiPrompts
    });
  }

  public async updateConfig(config: Partial<MusicGenerationConfig>) {
    if (!this.session) return;

    // Default config merged with updates
    const fullConfig: MusicGenerationConfig = {
        bpm: 90,
        temperature: 1.0,
        audioFormat: "pcm16",
        sampleRateHz: SAMPLE_RATE,
        ...config
    };

    await this.session.setMusicGenerationConfig({
        musicGenerationConfig: fullConfig
    });
  }

  public setVolume(val: number) {
      if (this.gainNode) {
          this.gainNode.gain.value = val;
      }
  }
}

export const musicService = new MusicService();

import React, { useEffect, useRef } from 'react';
import { musicService } from '../services/musicService';

interface VisualizerProps {
  isPlaying: boolean;
}

const Visualizer: React.FC<VisualizerProps> = ({ isPlaying }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationRef = useRef<number>();

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const analyser = musicService.getAnalyser();

    const draw = () => {
      if (!analyser) {
        animationRef.current = requestAnimationFrame(draw);
        return;
      }

      const bufferLength = analyser.frequencyBinCount;
      const dataArray = new Uint8Array(bufferLength);
      analyser.getByteTimeDomainData(dataArray);

      ctx.clearRect(0, 0, canvas.width, canvas.height);
      ctx.lineWidth = 2;
      ctx.strokeStyle = '#e2e8f0'; // Light gray/white
      ctx.beginPath();

      const sliceWidth = (canvas.width * 1.0) / bufferLength;
      let x = 0;

      for (let i = 0; i < bufferLength; i++) {
        const v = dataArray[i] / 128.0;
        const y = (v * canvas.height) / 2;

        if (i === 0) {
          ctx.moveTo(x, y);
        } else {
          ctx.lineTo(x, y);
        }

        x += sliceWidth;
      }

      ctx.lineTo(canvas.width, canvas.height / 2);
      ctx.stroke();

      animationRef.current = requestAnimationFrame(draw);
    };

    if (isPlaying) {
      draw();
    } else {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      // Draw a flat line
      ctx.beginPath();
      ctx.moveTo(0, canvas.height / 2);
      ctx.lineTo(canvas.width, canvas.height / 2);
      ctx.strokeStyle = '#555';
      ctx.stroke();
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    }

    return () => {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, [isPlaying]);

  return (
    <canvas 
      ref={canvasRef} 
      width={400} 
      height={40} 
      className="w-full h-full opacity-60"
    />
  );
};

export default Visualizer;

import React from 'react';
import { WeightedPrompt } from '../types';

interface PromptLayerProps {
  prompts: WeightedPrompt[];
  onUpdate: (id: string, newWeight: number) => void;
  onToggle: (id: string) => void;
}

const PromptLayer: React.FC<PromptLayerProps> = ({ prompts, onUpdate, onToggle }) => {
  return (
    <div className="w-full max-w-3xl flex flex-col gap-3 mb-6">
      {prompts.map((prompt) => (
        <div 
          key={prompt.id} 
          className={`relative group h-20 rounded-2xl flex items-center px-6 transition-all duration-300 overflow-hidden ${prompt.isActive ? 'bg-[#1a1a1a]' : 'bg-neutral-900 opacity-50'}`}
        >
          {/* Background Fill representing Weight */}
          <div 
            className="absolute left-0 top-0 bottom-0 transition-all duration-100 ease-out opacity-20"
            style={{ 
              width: `${prompt.weight * 100}%`,
              backgroundColor: prompt.color
            }}
          />

          {/* Slider Input Overlay */}
          <input
            type="range"
            min="0"
            max="1"
            step="0.01"
            value={prompt.weight}
            onChange={(e) => onUpdate(prompt.id, parseFloat(e.target.value))}
            className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
            disabled={!prompt.isActive}
          />

          {/* Visual Track */}
          <div className="relative flex-1 flex items-center justify-between z-0 pointer-events-none">
             <span 
               className="text-2xl font-bold tracking-tight"
               style={{ color: prompt.isActive ? prompt.color : '#666' }}
             >
               {prompt.text}
             </span>

             {/* Custom Thumb Visual (follows the weight) */}
             <div className="absolute h-10 w-20 rounded-full bg-white/10 border border-white/20 backdrop-blur-sm shadow-lg pointer-events-none transform -translate-x-1/2"
                style={{ left: `${prompt.weight * 100}%` }}
             >
                <div 
                   className="absolute inset-2 rounded-full opacity-80"
                   style={{ backgroundColor: '#111' }}
                />
             </div>
          </div>

          {/* Toggle Switch */}
          <button 
             onClick={(e) => {
               e.stopPropagation(); // prevent drag
               onToggle(prompt.id);
             }}
             className="relative z-20 ml-6 w-12 h-6 rounded-full bg-neutral-800 flex items-center p-1 transition-colors"
             style={{ backgroundColor: prompt.isActive ? prompt.color : '#333' }}
          >
             <div 
               className={`w-4 h-4 bg-black rounded-full shadow-md transform transition-transform ${prompt.isActive ? 'translate-x-6' : 'translate-x-0'}`}
             />
          </button>
        </div>
      ))}
    </div>
  );
};

export default PromptLayer;

import React from 'react';
import { MacroLevel, MacroState, InstrumentState } from '../types';

interface ControlDeckProps {
  macroState: MacroState;
  instrumentState: InstrumentState;
  onMacroChange: (key: keyof MacroState, val: MacroLevel) => void;
  onInstrumentToggle: (key: keyof InstrumentState) => void;
}

const MacroControl: React.FC<{
  label: string;
  value: MacroLevel;
  onChange: (val: MacroLevel) => void;
  icon: React.ReactNode;
}> = ({ label, value, onChange, icon }) => {
  const options: MacroLevel[] = ['low', 'med', 'high'];

  return (
    <div className="flex flex-col items-center gap-2">
      <div className="flex bg-[#111] rounded-full p-1 border border-white/5">
         <div className="flex items-center justify-center w-12 h-12 rounded-full bg-[#222] text-white">
            {icon}
         </div>
         <div className="flex items-center gap-1 px-3">
            {options.map((opt) => (
               <button
                 key={opt}
                 onClick={() => onChange(opt)}
                 className={`w-4 h-4 rounded-full border border-white/10 transition-all ${
                    value === opt ? 'bg-white scale-110' : 'bg-transparent hover:bg-white/20'
                 } ${opt === 'high' ? 'w-5 h-5' : opt === 'med' ? 'w-4 h-4' : 'w-3 h-3'}`}
                 aria-label={`Set ${label} to ${opt}`}
               />
            ))}
         </div>
      </div>
      <span className="text-xs text-neutral-400 font-medium tracking-wider uppercase">{label}</span>
    </div>
  );
};

const InstrumentControl: React.FC<{
  label: string;
  active: boolean;
  onToggle: () => void;
}> = ({ label, active, onToggle }) => {
  return (
    <div className="flex flex-col items-center gap-2">
        <button 
           onClick={onToggle}
           className={`w-12 h-12 rounded-full flex items-center justify-center transition-all ${active ? 'bg-[#222] text-[#4fd1c5]' : 'bg-[#111] text-neutral-600'}`}
        >
           {/* Simple Speaker Icon */}
           <svg xmlns="http://www.w3.org/2000/svg" fill="currentColor" viewBox="0 0 24 24" className="w-6 h-6">
              <path d="M13.5 4.06c0-1.336-1.616-2.005-2.56-1.06l-4.5 4.5H4.508c-1.141 0-2.318.664-2.66 1.905A9.76 9.76 0 001.5 12c0 .898.121 1.768.35 2.595.341 1.24 1.518 1.905 2.659 1.905h1.93l4.5 4.5c.945.945 2.561.276 2.561-1.06V4.06zM18.58 12a8.724 8.724 0 00-3.045-6.65.6.6 0 11.782-.916A9.927 9.927 0 0119.78 12a9.922 9.922 0 01-3.464 7.566.6.6 0 11-.782-.916A8.724 8.724 0 0018.58 12z" />
           </svg>
        </button>
        <span className="text-xs text-neutral-400 font-medium tracking-wider uppercase">{label}</span>
    </div>
  )
};

const ControlDeck: React.FC<ControlDeckProps> = ({ 
    macroState, instrumentState, onMacroChange, onInstrumentToggle 
}) => {
  return (
    <div className="w-full max-w-4xl bg-[#161616] rounded-[3rem] p-6 px-10 flex items-center justify-between border border-white/5 shadow-2xl">

      {/* Density */}
      <MacroControl 
         label="Density" 
         value={macroState.density} 
         onChange={(v) => onMacroChange('density', v)}
         icon={<svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-5.714 2.143L13 21l-2.286-6.857L5 12l5.714-2.143L13 3z" /></svg>}
      />

      <div className="h-10 w-px bg-white/10 mx-2" />

      {/* Brightness */}
      <MacroControl 
         label="Brightness" 
         value={macroState.brightness} 
         onChange={(v) => onMacroChange('brightness', v)}
         icon={<svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364 6.364l-.707-.707M6.343 6.343l-.707-.707m12.728 0l-.707.707M6.343 17.657l-.707.707M16 12a4 4 0 11-8 0 4 4 0 018 0z" /></svg>}
      />

      <div className="h-10 w-px bg-white/10 mx-2" />

      {/* Chaos */}
      <MacroControl 
         label="Chaos" 
         value={macroState.chaos} 
         onChange={(v) => onMacroChange('chaos', v)}
         icon={<svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z" /></svg>}
      />

      <div className="h-10 w-px bg-white/10 mx-2" />

      {/* Instrument Toggles */}
      <InstrumentControl 
         label="Drums" 
         active={instrumentState.drums} 
         onToggle={() => onInstrumentToggle('drums')} 
      />
      <InstrumentControl 
         label="Bass" 
         active={instrumentState.bass} 
         onToggle={() => onInstrumentToggle('bass')} 
      />
      <InstrumentControl 
         label="Other" 
         active={instrumentState.other} 
         onToggle={() => onInstrumentToggle('other')} 
      />

    </div>
  );
