export default ControlDeck;

import React, { useState, useEffect, useCallback } from 'react';
import PromptLayer from './components/PromptLayer';
import ControlDeck from './components/ControlDeck';
import Visualizer from './components/Visualizer';
import { DEFAULT_PROMPTS, SUGGESTIONS } from './constants';
import { WeightedPrompt, MacroState, InstrumentState, MacroLevel } from './types';
import { musicService } from './services/musicService';

export default function App() {
  const [isPlaying, setIsPlaying] = useState(false);
  const [prompts, setPrompts] = useState<WeightedPrompt[]>(DEFAULT_PROMPTS);
  const [textInput, setTextInput] = useState('');

  const [macroState, setMacroState] = useState<MacroState>({
    density: 'med',
    brightness: 'med',
    chaos: 'low'
  });

  const [instrumentState, setInstrumentState] = useState<InstrumentState>({
    drums: true,
    bass: true,
    other: true
  });

  // Debounce Prompt Updates to API
  const updateApiPrompts = useCallback(async (currentPrompts: WeightedPrompt[]) => {
    if (isPlaying) {
       // In a real app, debounce this to avoid flooding API
       await musicService.setPrompts(currentPrompts);
    }
  }, [isPlaying]);

  const handlePromptWeightChange = (id: string, newWeight: number) => {
    const updated = prompts.map(p => 
      p.id === id ? { ...p, weight: newWeight } : p
    );
    setPrompts(updated);
    updateApiPrompts(updated);
  };

  const handlePromptToggle = (id: string) => {
    const updated = prompts.map(p => 
      p.id === id ? { ...p, isActive: !p.isActive } : p
    );
    setPrompts(updated);
    updateApiPrompts(updated);
  };

  const handleRemovePrompt = (id: string) => {
     const updated = prompts.filter(p => p.id !== id);
     setPrompts(updated);
     updateApiPrompts(updated);
  };

  const handleAddPrompt = (text: string) => {
    if (!text) return;
    const newPrompt: WeightedPrompt = {
      id: Date.now().toString(),
      text: text,
      weight: 0.5,
      color: ['#cba6f7', '#f9e2af', '#9dffc0', '#f38ba8'][Math.floor(Math.random() * 4)],
      isActive: true
    };
    const updated = [newPrompt, ...prompts];
    setPrompts(updated);
    setTextInput('');
    updateApiPrompts(updated);
  };

  const togglePlay = async () => {
    try {
      if (!isPlaying) {
        // First play requires user interaction for AudioContext
        await musicService.play();
        // Send initial prompts
        await musicService.setPrompts(prompts);
      } else {
        // For this demo, we just stop visualizer state, 
        // effectively "pausing" is complex with streaming but we simulate toggle
        // musicService.pause() - implementation depends on specific lyria method
      }
      setIsPlaying(!isPlaying);
    } catch (e) {
      console.error("Error toggling play:", e);
      alert("Please set your API KEY in constants.ts or ensure env variables are set.");
    }
  };

  const updateConfig = async () => {
    // This maps macro controls to actual generation config params (Temperature, BPM, etc.)
    // Logic is simplified for demo purposes
    let temp = 1.0;
    if (macroState.chaos === 'low') temp = 0.8;
    if (macroState.chaos === 'high') temp = 1.3;

    let bpm = 90;
    if (macroState.density === 'high') bpm = 110;
    if (macroState.density === 'low') bpm = 70;

    await musicService.updateConfig({
        bpm,
        temperature: temp,
    });
  };

  // Update config when macros change
  useEffect(() => {
     if (isPlaying) {
        updateConfig();
     }
  }, [macroState]);


  return (
    <div className="min-h-screen w-full flex flex-col items-center justify-between p-6 relative font-sans">

      {/* Header */}
      <div className="w-full flex justify-between items-center mb-8">
         <div className="flex items-center gap-2">
            <h1 className="text-2xl font-semibold tracking-tight">MusicFX DJ</h1>
            <button className="bg-[#222] rounded-full px-3 py-1 text-xs font-medium text-neutral-400">▼</button>
         </div>
         <div className="flex items-center gap-4">
             <button className="w-8 h-8 rounded-full bg-[#222] flex items-center justify-center text-neutral-400 text-sm">?</button>
             <button className="w-8 h-8 rounded-full bg-[#222] flex items-center justify-center text-neutral-400">⋮</button>
