  const [textInput, setTextInput] = useState('');

  const [macroState, setMacroState] = useState<MacroState>({
    density: 'auto',
    brightness: 'auto',
    chaos: 'auto'
  });

  const [instrumentState, setInstrumentState] = useState<InstrumentState>({
    drums: true,
    bass: true,
    other: true
  });

  // Debounce Prompt Updates to API
  const updateApiPrompts = useCallback(async (currentPrompts: WeightedPrompt[]) => {
    if (isPlaying) {
       await musicService.setPrompts(currentPrompts);
    }
  }, [isPlaying]);

  const handlePromptWeightChange = (id: string, newWeight: number) => {
    const updated = prompts.map(p => 
      p.id === id ? { ...p, weight: newWeight } : p
    );
    setPrompts(updated);
    updateApiPrompts(updated);
  };

  const handlePromptToggle = (id: string) => {
    const updated = prompts.map(p => 
      p.id === id ? { ...p, isActive: !p.isActive } : p
    );
    setPrompts(updated);
    updateApiPrompts(updated);
  };

  const handleAddPrompt = (text: string) => {
    if (!text) return;
    const newPrompt: WeightedPrompt = {
      id: Date.now().toString(),
      text: text,
      weight: 0.5,
      color: ['#cba6f7', '#f9e2af', '#9dffc0', '#f38ba8'][Math.floor(Math.random() * 4)],
      isActive: true
    };
    const updated = [newPrompt, ...prompts];
    setPrompts(updated);
    setTextInput('');
    updateApiPrompts(updated);
  };

  const togglePlay = async () => {
    try {
      if (!isPlaying) {
        await musicService.play();
        await musicService.setPrompts(prompts);
        // Ensure initial config is sent
        updateConfig();
      }
      setIsPlaying(!isPlaying);
    } catch (e) {
      console.error("Error toggling play:", e);
      alert("Please set your API KEY in constants.ts or ensure env variables are set.");
    }
  };

  const updateConfig = async () => {
    const config: MusicGenerationConfig = {};

    // 1. Map Sliders to API parameters
    // Density & Brightness are supported directly.
    // If 'auto', we omit them from the config, letting the model decide (or we could pass undefined, but partial object is cleaner).
    if (macroState.density !== 'auto') {
        config.density = macroState.density as number;
    }

    if (macroState.brightness !== 'auto') {
        config.brightness = macroState.brightness as number;
    }

    // Chaos maps to Temperature (0.0 - 3.0)
    // Default is 1.1.
    // We map UI 0.0-1.0 to API 0.0-3.0
    if (macroState.chaos !== 'auto') {
        config.temperature = (macroState.chaos as number) * 3.0;
    } else {
        config.temperature = 1.1; // Default
    }

    // 2. Map Instrument Toggles
    // The API supports: mute_bass, mute_drums, only_bass_and_drums
    // Logic:
    // If Drums OFF -> mute_drums = true
    // If Bass OFF -> mute_bass = true
    // If Other OFF -> only_bass_and_drums = true (This implies we only want bass and drums, effecitvely muting others)

    // However, only_bass_and_drums logic is "Steer the model to try to only output bass and drums".
    // It doesn't strictly mute "other" in a mixer sense, but prompts the model.

    config.mute_drums = !instrumentState.drums;
    config.mute_bass = !instrumentState.bass;
    config.only_bass_and_drums = !instrumentState.other;

    // Send update
    await musicService.updateConfig(config);
  };

  // Update config when macros or instruments change
  useEffect(() => {
     if (isPlaying) {
        updateConfig();
     }
  }, [macroState, instrumentState]);


  return (
    <div className="min-h-screen w-full flex flex-col items-center justify-between p-6 relative font-sans">

      {/* Header */}
      <div className="w-full flex justify-between items-center mb-8">
         <div className="flex items-center gap-2">
            <h1 className="text-2xl font-semibold tracking-tight">MusicFX DJ</h1>
            <button className="bg-[#222] rounded-full px-3 py-1 text-xs font-medium text-neutral-400">▼</button>
         </div>
         <div className="flex items-center gap-4">
             <button className="w-8 h-8 rounded-full bg-[#222] flex items-center justify-center text-neutral-400 text-sm">?</button>
             <button className="w-8 h-8 rounded-full bg-[#222] flex items-center justify-center text-neutral-400">⋮</button>
             <div className="w-8 h-8 rounded-full bg-blue-500 flex items-center justify-center text-white font-bold text-xs">A</div>
         </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 w-full max-w-3xl flex flex-col items-center justify-center relative z-10">

         <PromptLayer 
           prompts={prompts} 
           onUpdate={handlePromptWeightChange} 
           onToggle={handlePromptToggle}
         />

         {/* Add Prompt Input */}
         <div className="w-full max-w-3xl mb-8 relative group">
            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                <span className="text-neutral-500 text-lg">+</span>
            </div>
            <input 
              type="text" 
              value={textInput}
              onChange={(e) => setTextInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleAddPrompt(textInput)}
              placeholder="Add a prompt ..."
              className="w-full bg-[#111] rounded-2xl py-4 pl-10 pr-12 text-neutral-300 placeholder-neutral-600 focus:outline-none focus:ring-1 focus:ring-neutral-700 transition-all"
            />
            <div className="absolute inset-y-0 right-2 flex items-center gap-2">
               <button className="p-2 text-neutral-500 hover:text-white transition-colors">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
               </button>
               <button className="p-2 text-neutral-500 hover:text-white transition-colors">
                   <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
               </button>
            </div>
         </div>

         {/* Suggestions Pills */}
         <div className="w-full max-w-3xl flex flex-wrap gap-2 justify-center mb-8">
            <button className="px-4 py-2 rounded-xl bg-neutral-800 text-neutral-300 text-sm hover:bg-neutral-700 transition-colors flex items-center gap-2">
               <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
               more
            </button>
            {SUGGESTIONS.map(s => (
               <button 
                  key={s} 
                  onClick={() => handleAddPrompt(s)}
                  className="px-4 py-2 rounded-xl bg-neutral-900 text-neutral-400 text-sm hover:bg-neutral-800 transition-colors border border-neutral-800"
               >
                  {s}
               </button>
            ))}
         </div>

         {/* Control Deck */}
         <ControlDeck 
            macroState={macroState}
            instrumentState={instrumentState}
            onMacroChange={(k, v) => setMacroState(p => ({ ...p, [k]: v }))}
            onInstrumentToggle={(k) => setInstrumentState(p => ({ ...p, [k]: !p[k] }))}
         />

      </div>

      {/* Bottom Bar: Playback & Visualizer */}
      <div className="w-full max-w-4xl mt-6 bg-[#111] rounded-3xl p-3 flex items-center gap-4 border border-white/5">

         <button 
           onClick={togglePlay}
           className={`w-14 h-14 rounded-full flex items-center justify-center transition-all ${isPlaying ? 'bg-[#ff9cd6] text-black' : 'bg-[#333] text-white'}`}
         >
           {isPlaying ? (
              <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M6 4h4v16H6V4zm8 0h4v16h-4V4z"/></svg>
           ) : (
              <svg className="w-6 h-6 ml-1" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z"/></svg>
           )}
         </button>

         <button className="w-10 h-10 rounded-full bg-[#222] flex items-center justify-center text-neutral-400 hover:text-white">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
         </button>

         <button className="w-10 h-10 rounded-full bg-[#222] flex items-center justify-center text-neutral-400 hover:text-white">
             <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24"><path d="M14 3.23v2.06c2.89.86 5 3.54 5 6.71s-2.11 5.85-5 6.71v2.06c4.01-.91 7-4.49 7-8.77s-2.99-7.86-7-8.77zM16.5 12c0-1.77-1.02-3.29-2.5-4.03v8.05c1.48-.73 2.5-2.25 2.5-4.02zM3 9v6h4l5 5V4L7 9H3z"/></svg>
         </button>

         {/* Visualizer Area */}
         <div className="flex-1 h-10 bg-[#0a0a0a] rounded-lg overflow-hidden relative">
            <Visualizer isPlaying={isPlaying} />
            <div className="absolute top-1/2 left-1/2 w-0.5 h-full bg-white transform -translate-x-1/2 -translate-y-1/2" />
         </div>

         {/* Metadata */}
         <div className="flex items-center gap-2">
            <button className="px-3 py-2 rounded-lg bg-[#222] text-xs font-bold text-neutral-300">BPM</button>
            <button className="px-3 py-2 rounded-lg bg-[#222] text-xs font-bold text-neutral-300">KEY</button>
         </div>

         <button className="w-10 h-10 rounded-full bg-transparent flex items-center justify-center text-neutral-500 hover:text-white">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" /></svg>
         </button>

      </div>
    </div>
  );
}

export interface WeightedPrompt {
  id: string;
  text: string;
  weight: number;
  color: string;
  isActive: boolean;
}

export interface MusicGenerationConfig {
  bpm?: number;
  temperature?: number;
  density?: number; // 0.0 to 1.0
  brightness?: number; // 0.0 to 1.0
  mute_drums?: boolean;
  mute_bass?: boolean;
  only_bass_and_drums?: boolean;
}

// Defining the shape of the experimental Lyria API based on user request
export interface LyriaSession {
  setWeightedPrompts: (args: { weightedPrompts: { text: string; weight: number }[] }) => Promise<void>;
  setMusicGenerationConfig: (args: { musicGenerationConfig: MusicGenerationConfig }) => Promise<void>;
  reset_context: () => Promise<void>;
  play: () => Promise<void>;
  pause: () => Promise<void>; 
  close: () => Promise<void>;
}

export type MacroValue = number | 'auto';

export interface MacroState {
  density: MacroValue;
  brightness: MacroValue;
  chaos: MacroValue;
}

export interface InstrumentState {
  drums: boolean;
  bass: boolean;
  other: boolean;
}

import { GoogleGenAI } from "@google/genai";
import { API_KEY, SAMPLE_RATE } from "../constants";
import { LyriaSession, MusicGenerationConfig, WeightedPrompt } from "../types";

class MusicService {
  private client: GoogleGenAI;
  private session: LyriaSession | null = null;
  private audioContext: AudioContext | null = null;
  private nextStartTime: number = 0;
  private analyser: AnalyserNode | null = null;
  private gainNode: GainNode | null = null;
  private isConnected: boolean = false;

  // Simulation State
  private isSimulation: boolean = false;
  private simulationInterval: number | null = null;
  private activeNodes: AudioNode[] = [];

  // Default config matching API defaults
  private currentConfig: MusicGenerationConfig = {
      bpm: 90,
      temperature: 1.1,
      density: 0.5,
      brightness: 0.5,
  };

  constructor() {
    this.client = new GoogleGenAI({
      apiKey: API_KEY,
      apiVersion: "v1alpha",
    });
  }

  // Initialize Audio Context
  private initAudioContext() {
    if (!this.audioContext) {
      this.audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({
        sampleRate: SAMPLE_RATE,
      });
      this.analyser = this.audioContext.createAnalyser();
      this.analyser.fftSize = 256;
      this.gainNode = this.audioContext.createGain();

      // Connect graph: Source -> Gain -> Analyser -> Destination
      this.gainNode.connect(this.analyser);
      this.analyser.connect(this.audioContext.destination);
    }
  }

  public getAnalyser(): AnalyserNode | null {
    return this.analyser;
  }

  public async connect(): Promise<void> {
    if (this.isConnected) return;
    this.initAudioContext();

    try {
      const musicClient = (this.client as any).live?.music;

      // Attempt real connection
      if (musicClient && API_KEY) {
        console.log("Connecting to Lyria model...");
        try {
            this.session = await musicClient.connect({
                model: "models/lyria-realtime-exp",
                callbacks: {
                onmessage: (message: any) => {
                    if (message.serverContent?.audioChunks) {
                    for (const chunk of message.serverContent.audioChunks) {
                        this.scheduleAudioChunk(chunk.data);
                    }
                    }
                },
                onerror: (error: any) => {
                    console.error("Music session error:", error);
                },
                onclose: () => {
                    console.log("Lyria RealTime stream closed.");
                    this.isConnected = false;
                },
                },
            });
            this.isConnected = true;
            console.log("Connected to Lyria.");
            return;
        } catch (innerError) {
             console.warn("Real Lyria connection failed, switching to Mock.", innerError);
        }
      } else {
        console.warn("No API Key or Music Client found, switching to Mock.");
      }

      // Fallback to Simulation
      this.isSimulation = true;
      this.isConnected = true;

      this.session = {
          setWeightedPrompts: async (args) => {
              console.log("[Simulation] Prompts updated:", args.weightedPrompts);
          },
          setMusicGenerationConfig: async (args) => {
              this.currentConfig = { ...this.currentConfig, ...args.musicGenerationConfig };
              this.updateSimulationParams();
          },
          reset_context: async () => {
              console.log("[Simulation] Context reset");
              this.stopSimulationLoop();
              this.startSimulationLoop();
          },
          play: async () => {
              this.startSimulationLoop();
          },
          pause: async () => {
              this.stopSimulationLoop();
          },
          close: async () => {
              this.stopSimulationLoop();
              this.isConnected = false;
          }
      };

      console.log("Connected to Lyria (Simulation Mode).");

    } catch (e) {
      console.error("Fatal error in connect:", e);
      throw e;
    }
  }

  private base64ToArrayBuffer(base64: string): ArrayBuffer {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes.buffer;
  }

  private scheduleAudioChunk(base64Data: string) {
    if (!this.audioContext || !this.gainNode) return;

    const rawBuffer = this.base64ToArrayBuffer(base64Data);
    if (rawBuffer.byteLength === 0) return;

    const int16Data = new Int16Array(rawBuffer);
    const float32Data = new Float32Array(int16Data.length);

    for (let i = 0; i < int16Data.length; i++) {
      float32Data[i] = int16Data[i] / 32768.0;
    }

    const channels = 2;
    const frameCount = int16Data.length / channels;
    if (frameCount === 0) return;

    const audioBuffer = this.audioContext.createBuffer(channels, frameCount, SAMPLE_RATE);
    const leftChannel = audioBuffer.getChannelData(0);
    const rightChannel = audioBuffer.getChannelData(1);

    for (let i = 0; i < frameCount; i++) {
        leftChannel[i] = float32Data[i * 2];
        rightChannel[i] = float32Data[i * 2 + 1];
    }

    const source = this.audioContext.createBufferSource();
    source.buffer = audioBuffer;
    source.connect(this.gainNode);

    const currentTime = this.audioContext.currentTime;
    if (this.nextStartTime < currentTime) {
      this.nextStartTime = currentTime;
    }

    source.start(this.nextStartTime);
    this.nextStartTime += audioBuffer.duration;
  }

  // --- Simulation Logic ---

  private startSimulationLoop() {
      if (this.simulationInterval) return;
      this.generateDrone();
      this.simulationInterval = window.setInterval(() => {
          this.generateDrone();
      }, 4000);
  }

  private stopSimulationLoop() {
      if (this.simulationInterval) {
          clearInterval(this.simulationInterval);
          this.simulationInterval = null;
      }
      this.activeNodes.forEach(n => {
          try { (n as any).stop?.(); } catch(e){}
          n.disconnect();
      });
      this.activeNodes = [];
  }

  private updateSimulationParams() {
      // Simulation param updates
  }

  private generateDrone() {
      if (!this.audioContext || !this.gainNode) return;

      const oldNodes = [...this.activeNodes];
      this.activeNodes = [];

      const densityVal = this.currentConfig.density ?? 0.5;
      const brightnessVal = this.currentConfig.brightness ?? 0.5;
      const chaosVal = this.currentConfig.temperature ?? 1.1;

      const layers = Math.max(1, Math.floor(densityVal * 5));
      const baseFreq = 55;

      for (let i = 0; i < layers; i++) {
          const osc = this.audioContext.createOscillator();
          const gain = this.audioContext.createGain();
          const filter = this.audioContext.createBiquadFilter();

          const ratio = [1, 1.5, 1.33, 2, 0.5][Math.floor(Math.random() * 5)];
          osc.frequency.value = baseFreq * ratio * (i + 1);
          osc.type = i % 2 === 0 ? 'sine' : 'triangle';

          const detune = (Math.random() - 0.5) * (chaosVal * 200);
          osc.detune.value = detune;

          filter.type = 'lowpass';
          const cutoff = 200 + (brightnessVal * 1800) + (Math.random() * 200);
          filter.frequency.value = cutoff;

          const now = this.audioContext.currentTime;
          gain.gain.setValueAtTime(0, now);
          gain.gain.linearRampToValueAtTime(0.1 / layers, now + 1);
          gain.gain.exponentialRampToValueAtTime(0.001, now + 4);

          osc.connect(filter);
          filter.connect(gain);
          gain.connect(this.gainNode);

          osc.start(now);
          osc.stop(now + 4.1);

          this.activeNodes.push(osc, gain, filter);
      }

      setTimeout(() => {
          oldNodes.forEach(n => {
            n.disconnect();
          });
      }, 4500);
  }

  public async play() {
    // Only call session.play() if connected. 
    // Usually usage pattern is connect() -> setPrompts() -> setConfig() -> play()
    // This method is just a wrapper for session.play() now
    if (!this.session) return; // Should connect first

    if (this.audioContext?.state === 'suspended') {
      await this.audioContext.resume();
    }
    await this.session.play();
  }

  public async setPrompts(prompts: WeightedPrompt[]) {
    if (!this.session) return;

    const apiPrompts = prompts
      .filter(p => p.isActive)
      .map(p => ({
        text: p.text,
        weight: p.weight
      }));

    if (apiPrompts.length === 0) return;

    await this.session.setWeightedPrompts({
      weightedPrompts: apiPrompts
    });
  }

  public async updateConfig(config: Partial<MusicGenerationConfig>) {
    if (!this.session) return;

    // Merge new config with defaults and current state
    const fullConfig: MusicGenerationConfig = {
        ...this.currentConfig,
        ...config
    };
    this.currentConfig = fullConfig;

    await this.session.setMusicGenerationConfig({
        musicGenerationConfig: fullConfig
    });
  }

  public async resetContext() {
      if (this.session?.reset_context) {
          await this.session.reset_context();
      }
  }

  public setVolume(val: number) {
      if (this.gainNode) {
          this.gainNode.gain.value = val;
      }
  }
}

export const musicService = new MusicService();

import React from 'react';
import { MacroValue, MacroState, InstrumentState } from '../types';

interface ControlDeckProps {
  macroState: MacroState;
  instrumentState: InstrumentState;
  onMacroChange: (key: keyof MacroState, val: MacroValue) => void;
  onInstrumentToggle: (key: keyof InstrumentState) => void;
}

