  label: string;
  value: MacroValue;
  onChange: (val: MacroValue) => void;
}> = ({ label, value, onChange }) => {
  const isAuto = value === 'auto';
  // Use a middle value for visualization when in Auto mode, but actual value for logic
  const numericValue = isAuto ? 0.5 : (value as number);

  const handleSliderChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    // When slider moves, it automatically becomes a number (manual mode)
    onChange(parseFloat(e.target.value));
  };

  return (
    <div className="flex flex-col items-center gap-3">
      <div className="flex bg-[#161616] rounded-full p-1.5 border border-white/10 items-center w-48 h-14 relative shadow-inner">

         {/* Auto Button (Star) */}
         <button
            onClick={() => onChange('auto')}
            className={`w-11 h-11 rounded-full flex items-center justify-center transition-all duration-300 shrink-0 z-20 ${
                isAuto 
                  ? 'bg-white text-black shadow-[0_0_15px_rgba(255,255,255,0.4)] scale-100' 
                  : 'bg-[#222] text-neutral-600 hover:text-neutral-300 hover:bg-[#2a2a2a] scale-95'
            }`}
         >
