}

import React, { useState } from 'react';
import { WeightedPrompt } from '../types';

interface PromptLayerProps {
  prompts: WeightedPrompt[];
  onUpdate: (id: string, newWeight: number) => void;
  onToggle: (id: string) => void;
  onDelete: (id: string) => void;
  onEdit: (id: string, newText: string) => void;
}

const PromptLayer: React.FC<PromptLayerProps> = ({ prompts, onUpdate, onToggle, onDelete, onEdit }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');

  const startEditing = (prompt: WeightedPrompt) => {
    setEditingId(prompt.id);
    setEditValue(prompt.text);
  };

  const saveEdit = (id: string) => {
    if (editValue.trim()) {
      onEdit(id, editValue.trim());
    }
    setEditingId(null);
  };

  const handleKeyDown = (e: React.KeyboardEvent, id: string) => {
    if (e.key === 'Enter') saveEdit(id);
    if (e.key === 'Escape') setEditingId(null);
  };

  return (
    <div className="w-full max-w-3xl flex flex-col gap-4 mb-8">
      {prompts.map((prompt) => (
        <div 
          key={prompt.id} 
          className={`relative group h-20 rounded-2xl flex items-center transition-all duration-300 overflow-hidden ${
            prompt.isActive ? 'bg-[#121212] ring-1 ring-white/5 shadow-xl' : 'bg-neutral-900/50 opacity-40 grayscale'
          }`}
        >
          {/* Background Fill representing Weight - Track-like experience */}
          <div 
            className="absolute left-0 top-0 bottom-0 transition-all duration-150 ease-out opacity-20 pointer-events-none"
            style={{ 
              width: `${prompt.weight * 100}%`,
              backgroundColor: prompt.color
            }}
          />

          {/* Interactive Range Input - Z-10 */}
          <input
            type="range"
            min="0"
            max="1"
            step="0.01"
            value={prompt.weight}
            onChange={(e) => onUpdate(prompt.id, parseFloat(e.target.value))}
            className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
            disabled={!prompt.isActive || editingId === prompt.id}
          />

          {/* Controls Layer - Z-20 - High visibility buttons */}
          <div className="relative z-20 flex items-center w-full h-full px-5 gap-4 pointer-events-none">

            {/* Left Actions: Edit & Delete - Visible without hover, but subtly dimmed */}
            <div className="flex items-center gap-2 pointer-events-auto">
               <button 
                 onClick={(e) => { e.stopPropagation(); startEditing(prompt); }}
                 className="w-9 h-9 flex items-center justify-center rounded-xl bg-white/5 hover:bg-white/10 text-neutral-400 hover:text-white transition-all active:scale-90 border border-white/5"
                 title="Edit"
               >
                 <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-4 h-4">
                   <path d="m2.695 14.762-1.262 3.155a.5.5 0 0 0 .65.65l3.155-1.262a4 4 0 0 0 1.343-.886L17.5 5.501a2.121 2.121 0 0 0-3-3L3.58 13.419a4 4 0 0 0-.885 1.343Z" />
                 </svg>
               </button>
               <button 
                 onClick={(e) => { e.stopPropagation(); onDelete(prompt.id); }}
                 className="w-9 h-9 flex items-center justify-center rounded-xl bg-white/5 hover:bg-red-500/10 text-neutral-400 hover:text-red-400 transition-all active:scale-90 border border-white/5"
                 title="Delete"
               >
                 <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-4 h-4">
                   <path fillRule="evenodd" d="M8.75 3A2.75 2.75 0 0 0 6 5.75v.67c-.158.014-.316.03-.474.048L4.047 6.67a.75.75 0 1 0 .176 1.49l.115-.013H15.66l.115.013a.75.75 0 0 0 .176-1.49l-1.479-.172A4.823 4.823 0 0 0 14 6.42v-.67A2.75 2.75 0 0 0 11.25 3h-2.5ZM7.5 5.75c0-.69.56-1.25 1.25-1.25h2.5c.69 0 1.25.56 1.25 1.25v.622c-.615-.02-1.235-.031-1.859-.031H8.11c-.624 0-1.244.01-1.859.031v-.622ZM4.857 9.442a.75.75 0 0 0-1.014.274l-.223.385a.75.75 0 0 0 .274 1.014l.223-.385a.75.75 0 0 0-.274-1.014l.223-.385ZM12.35 18.25A2.75 2.75 0 0 0 15 15.5v-5h-1.5v5c0 .69-.56 1.25-1.25 1.25h-4.5c-.69 0-1.25-.56-1.25-1.25v-5H5v5a2.75 2.75 0 0 0 2.75 2.75h4.6ZM9.25 11a.75.75 0 0 1 .75.75v3.5a.75.75 0 0 1-1.5 0v-3.5a.75.75 0 0 1 .75-.75Zm2.25.75a.75.75 0 0 0-1.5 0v3.5a.75.75 0 0 0 1.5 0v-3.5Z" clipRule="evenodd" />
                 </svg>
               </button>
            </div>

            {/* Content Area */}
            <div className="flex-1 min-w-0">
              {editingId === prompt.id ? (
                <div className="pointer-events-auto">
                  <input
                    autoFocus
                    className="bg-neutral-800 border border-white/20 rounded-xl px-4 py-2 text-xl font-bold text-white w-full focus:outline-none focus:ring-2 focus:ring-white/10"
                    value={editValue}
                    onChange={(e) => setEditValue(e.target.value)}
                    onBlur={() => saveEdit(prompt.id)}
                    onKeyDown={(e) => handleKeyDown(e, prompt.id)}
                    onClick={(e) => e.stopPropagation()}
                  />
                </div>
              ) : (
                <div className="flex flex-col">
                  <span 
                    className="text-2xl font-bold tracking-tight block truncate transition-colors duration-300"
                    style={{ color: prompt.isActive ? prompt.color : '#444' }}
                  >
                    {prompt.text}
                  </span>
                  <div className="flex items-center gap-1.5 mt-0.5">
                     <div className="h-1 w-12 bg-white/5 rounded-full overflow-hidden">
                        <div 
                          className="h-full bg-white/40 rounded-full" 
                          style={{ width: `${prompt.weight * 100}%` }} 
                        />
                     </div>
                     <span className="text-[10px] font-mono text-neutral-500 uppercase tracking-tighter">Weight {Math.round(prompt.weight * 100)}%</span>
                  </div>
                </div>
              )}
            </div>

            {/* Status & Toggle */}
            <div className="flex items-center gap-4 pointer-events-auto">
               <button 
                 onClick={(e) => {
                   e.stopPropagation();
                   onToggle(prompt.id);
                 }}
                 className={`relative shrink-0 w-12 h-6 rounded-full transition-all duration-300 flex items-center p-1 ${
                   prompt.isActive ? 'shadow-[0_0_10px_rgba(255,255,255,0.1)]' : 'bg-neutral-800'
                 }`}
                 style={{ backgroundColor: prompt.isActive ? prompt.color : '#222' }}
               >
                 <div 
                   className={`w-4 h-4 bg-black/80 rounded-full shadow-md transform transition-transform duration-300 ${
                     prompt.isActive ? 'translate-x-6' : 'translate-x-0'
                   }`}
                 />
               </button>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
};

export default PromptLayer;

export interface WeightedPrompt {
  id: string;
  text: string;
  weight: number;
  color: string;
  isActive: boolean;
}

export interface MusicGenerationConfig {
  bpm?: number;
  temperature?: number;
  density?: number; // 0.0 to 1.0
  brightness?: number; // 0.0 to 1.0
  mute_drums?: boolean;
  mute_bass?: boolean;
  only_bass_and_drums?: boolean;
}

// Defining the shape of the experimental Lyria API based on user request
export interface LyriaSession {
  setWeightedPrompts: (args: { weightedPrompts: { text: string; weight: number }[] }) => Promise<void>;
  setMusicGenerationConfig: (args: { musicGenerationConfig: MusicGenerationConfig }) => Promise<void>;
  reset_context: () => Promise<void>;
  play: () => Promise<void>;
  pause: () => Promise<void>; 
  close: () => Promise<void>;
}

export type MacroValue = number | 'auto';

export interface MacroState {
  density: MacroValue;
  brightness: MacroValue;
  chaos: MacroValue;
  bpm: MacroValue;
}

export interface InstrumentState {
  drums: boolean;
  bass: boolean;
  other: boolean;
}

import React, { useState } from 'react';
import { MacroValue } from '../types';

interface BpmPopupProps {
  currentBpm: MacroValue;
  onApply: (val: MacroValue) => void;
  onClose: () => void;
}

const BpmPopup: React.FC<BpmPopupProps> = ({ currentBpm, onApply, onClose }) => {
  const [tempBpm, setTempBpm] = useState<MacroValue>(currentBpm);

  const handleSliderChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setTempBpm(parseInt(e.target.value, 10));
  };

  const handleReset = () => {
    setTempBpm('auto');
  };

  return (
    <div className="absolute bottom-20 left-1/2 -translate-x-1/2 mb-2 z-[60] animate-in fade-in zoom-in duration-200 origin-bottom">
      <div className="bg-[#181818] w-72 p-6 rounded-[2rem] shadow-2xl border border-white/10 flex flex-col gap-6 relative">

        {/* BPM Display Area */}
        <div className="bg-[#222] rounded-2xl p-4 flex flex-col items-start gap-1">
          <span className="text-[10px] font-bold text-neutral-500 uppercase tracking-widest">BPM</span>
          <span className="text-3xl font-bold text-white leading-tight">
            {tempBpm === 'auto' ? 'Auto' : tempBpm}
          </span>
        </div>

        {/* Custom Slider */}
        <div className="relative h-4 flex items-center">
          <input
            type="range"
            min="40"
            max="180"
            value={tempBpm === 'auto' ? 100 : tempBpm}
            onChange={handleSliderChange}
            className="w-full h-2 rounded-full appearance-none bg-[#70214c] cursor-pointer z-20 outline-none"
            style={{
                background: `linear-gradient(to right, #ffccff ${tempBpm === 'auto' ? 0 : ((tempBpm as number - 40) / 140) * 100}%, #70214c ${tempBpm === 'auto' ? 0 : ((tempBpm as number - 40) / 140) * 100}%)`
            }}
          />
          {/* Custom Handle - using CSS to hide default and positioning this */}
          <style>{`
            input[type=range]::-webkit-slider-thumb {
              -webkit-appearance: none;
              height: 20px;
              width: 20px;
              border-radius: 50%;
              background: #181818;
              border: 2px solid white;
              cursor: pointer;
              margin-top: -1px;
            }
          `}</style>
        </div>

        <p className="text-center text-[11px] text-neutral-500 font-medium px-2 leading-relaxed">
          Adjusting the BPM during playback will cause the audio to restart
        </p>

        <div className="flex justify-end gap-6 pt-2">
          <button 
            onClick={handleReset}
            className="text-[#f9b2d8] text-sm font-bold hover:brightness-110 active:scale-95 transition-all"
          >
            Reset
          </button>
          <button 
            onClick={() => onApply(tempBpm)}
            className="text-[#f9b2d8] text-sm font-bold hover:brightness-110 active:scale-95 transition-all"
          >
            Apply
          </button>
        </div>

        {/* Triangle Pointer */}
        <div className="absolute -bottom-2 left-1/2 -translate-x-1/2 w-4 h-4 bg-[#181818] border-r border-b border-white/10 rotate-45" />
      </div>

      {/* Overlay to close when clicking outside */}
      <div 
        className="fixed inset-0 -z-10" 
        onClick={onClose}
      />
    </div>
  );
};

export default BpmPopup;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import PromptLayer from './components/PromptLayer';
import ControlDeck from './components/ControlDeck';
import Visualizer from './components/Visualizer';
import BpmPopup from './components/BpmPopup';
import { DEFAULT_PROMPTS, SUGGESTIONS } from './constants';
import { WeightedPrompt, MacroState, InstrumentState, MacroValue, MusicGenerationConfig } from './types';
import { musicService } from './services/musicService';

export default function App() {
  const [isPlaying, setIsPlaying] = useState(false);
  const [prompts, setPrompts] = useState<WeightedPrompt[]>(DEFAULT_PROMPTS);
  const [textInput, setTextInput] = useState('');
  const [showBpmPopup, setShowBpmPopup] = useState(false);

  const [macroState, setMacroState] = useState<MacroState>({
    density: 'auto',
    brightness: 'auto',
    chaos: 'auto',
    bpm: 'auto'
  });

  const [instrumentState, setInstrumentState] = useState<InstrumentState>({
    drums: true,
    bass: true,
    other: true
  });

  const updateApiPrompts = useCallback(async (currentPrompts: WeightedPrompt[]) => {
    if (isPlaying) {
       await musicService.setPrompts(currentPrompts);
    }
  }, [isPlaying]);

  const handlePromptWeightChange = (id: string, newWeight: number) => {
    const updated = prompts.map(p => 
      p.id === id ? { ...p, weight: newWeight } : p
    );
    setPrompts(updated);
    updateApiPrompts(updated);
  };

  const handlePromptToggle = (id: string) => {
    const updated = prompts.map(p => 
      p.id === id ? { ...p, isActive: !p.isActive } : p
    );
    setPrompts(updated);
    updateApiPrompts(updated);
  };

  const handleDeletePrompt = (id: string) => {
    const updated = prompts.filter(p => p.id !== id);
    setPrompts(updated);
    updateApiPrompts(updated);
  };

  const handleEditPrompt = (id: string, newText: string) => {
    const updated = prompts.map(p => 
      p.id === id ? { ...p, text: newText } : p
    );
    setPrompts(updated);
    updateApiPrompts(updated);
  };

  const handleAddPrompt = (text: string) => {
    if (!text) return;
    const newPrompt: WeightedPrompt = {
      id: Date.now().toString(),
      text: text,
      weight: 0.5,
      color: ['#cba6f7', '#f9e2af', '#9dffc0', '#f38ba8'][Math.floor(Math.random() * 4)],
      isActive: true
    };
    const updated = [newPrompt, ...prompts];
    setPrompts(updated);
    setTextInput('');
    updateApiPrompts(updated);
  };

  const togglePlay = async () => {
    try {
      if (!isPlaying) {
        await musicService.connect();
        await musicService.setPrompts(prompts);
        await updateConfig(); 
        await musicService.play();
      } else {
        await musicService.pause();
      }
      setIsPlaying(!isPlaying);
    } catch (e) {
      console.error("Error toggling play:", e);
      alert("Please ensure your API KEY is valid.");
    }
  };

  const updateConfigTimeout = useRef<number>(0);

  const updateConfig = async () => {
    const config: MusicGenerationConfig = {};
    if (macroState.density !== 'auto') config.density = macroState.density as number;
    if (macroState.brightness !== 'auto') config.brightness = macroState.brightness as number;
    if (macroState.bpm !== 'auto') config.bpm = macroState.bpm as number;

    if (macroState.chaos !== 'auto') {
        config.temperature = (macroState.chaos as number) * 3.0;
    } else {
        config.temperature = 1.1;
    }
    config.mute_drums = !instrumentState.drums;
    config.mute_bass = !instrumentState.bass;
    config.only_bass_and_drums = !instrumentState.other;

    await musicService.updateConfig(config);
  };

  const handleMacroChange = (key: keyof MacroState, val: MacroValue) => {
      setMacroState(prev => {
          const newState = { ...prev, [key]: val };
          if (isPlaying) {
            if (val === 'auto') {
                musicService.resetContext();
            } else if (key === 'chaos' || key === 'bpm') {
                 if (updateConfigTimeout.current) window.clearTimeout(updateConfigTimeout.current);
                 updateConfigTimeout.current = window.setTimeout(async () => {
                     await updateConfig();
                     await musicService.resetContext(); // Apply immediately
                 }, 200);
            }
          }
          return newState;
      });
  };

  const handleApplyBpm = (val: MacroValue) => {
      handleMacroChange('bpm', val);
      setShowBpmPopup(false);
  };

  useEffect(() => {
     if (isPlaying) {
         if (updateConfigTimeout.current) window.clearTimeout(updateConfigTimeout.current);
         updateConfigTimeout.current = window.setTimeout(() => {
             updateConfig();
         }, 150);
     }
  }, [macroState.density, macroState.brightness, macroState.chaos, instrumentState]);

  return (
    <div className="h-screen w-full flex flex-col bg-black overflow-hidden font-sans">

      {/* Scrollable Content Area */}
      <div className="flex-1 overflow-y-auto px-6 pt-6 pb-40">
        <div className="w-full max-w-5xl mx-auto">
          {/* Header */}
          <div className="w-full flex justify-between items-center mb-12">
             <div className="flex items-center gap-2">
                <h1 className="text-2xl font-semibold tracking-tight">MusicFX</h1>
             </div>
             <div className="flex items-center gap-4">
                 <button className="w-8 h-8 rounded-full bg-[#222] flex items-center justify-center text-neutral-400 text-sm">?</button>
                 <button className="w-8 h-8 rounded-full bg-[#222] flex items-center justify-center text-neutral-400">⋮</button>
            </div>
          </div>

          <div className="flex flex-col items-center">
             <PromptLayer 
               prompts={prompts} 
               onUpdate={handlePromptWeightChange} 
               onToggle={handlePromptToggle} 
               onDelete={handleDeletePrompt}
               onEdit={handleEditPrompt}
             />

             {/* Add Prompt Input */}
             <div className="w-full max-w-3xl mb-8 relative group">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                    <span className="text-neutral-500 text-lg">+</span>
                </div>
                <input 
                  type="text" 
                  value={textInput}
                  onChange={(e) => setTextInput(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleAddPrompt(textInput)}
                  placeholder="Add a prompt ..."
                  className="w-full bg-[#111] rounded-2xl py-4 pl-10 pr-12 text-neutral-300 placeholder-neutral-600 focus:outline-none focus:ring-1 focus:ring-neutral-700 transition-all border border-white/5"
                />
             </div>

             {/* Suggestions */}
             <div className="w-full max-w-3xl flex flex-wrap gap-2 justify-center mb-12">
                {SUGGESTIONS.map(s => (
                   <button 
                      key={s} 
                      onClick={() => handleAddPrompt(s)}
                      className="px-4 py-2 rounded-xl bg-neutral-900 text-neutral-400 text-sm hover:bg-neutral-800 transition-colors border border-neutral-800"
                   >
                      {s}
                   </button>
                ))}
             </div>

             <ControlDeck 
                macroState={macroState}
                instrumentState={instrumentState}
                onMacroChange={handleMacroChange}
                onInstrumentToggle={(k) => setInstrumentState(p => ({ ...p, [k]: !p[k] }))}
             />
          </div>
        </div>
      </div>

      {/* Fixed Bottom Bar */}
      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 w-full max-w-5xl px-6 z-50">

        {/* BPM Popup Integration */}
        {showBpmPopup && (
            <BpmPopup 
                currentBpm={macroState.bpm} 
                onApply={handleApplyBpm} 
                onClose={() => setShowBpmPopup(false)}
            />
        )}

        <div className="bg-[#111]/90 backdrop-blur-xl rounded-[2.5rem] p-3 flex items-center gap-4 border border-white/10 shadow-[0_20px_50px_rgba(0,0,0,0.5)]">
           <button 
             onClick={togglePlay}
             className={`w-14 h-14 rounded-full flex items-center justify-center transition-all shadow-lg ${isPlaying ? 'bg-[#ff9cd6] text-black' : 'bg-[#333] text-white'}`}
           >
             {isPlaying ? (
                <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M6 4h4v16H6V4zm8 0h4v16h-4V4z"/></svg>
             ) : (
                <svg className="w-6 h-6 ml-1" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z"/></svg>
             )}
           </button>

           <div className="flex-1 h-10 bg-[#0a0a0a] rounded-xl overflow-hidden relative border border-white/5">
              <Visualizer isPlaying={isPlaying} />
              <div className="absolute top-0 left-1/2 w-px h-full bg-white/20 transform -translate-x-1/2" />
           </div>

           <div className="flex items-center gap-2">
              <button 
                onClick={() => setShowBpmPopup(!showBpmPopup)}
                className={`min-w-[64px] px-3 py-2 rounded-lg bg-[#222] transition-colors border ${showBpmPopup ? 'border-[#ffccff]' : 'border-transparent'} flex flex-col items-center justify-center`}
              >
                 <span className="text-[10px] font-bold text-neutral-400 tracking-tighter uppercase">BPM</span>
                 <span className="text-xs font-bold text-white">
                    {macroState.bpm === 'auto' ? 'Auto' : macroState.bpm}
                 </span>
              </button>
              <button className="min-w-[48px] px-3 py-2 rounded-lg bg-[#222] flex items-center justify-center">
                 <span className="text-[10px] font-bold text-neutral-400 tracking-tighter uppercase">KEY</span>
              </button>
           </div>

           <button className="w-10 h-10 rounded-full flex items-center justify-center text-neutral-500 hover:text-white transition-colors">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" /></svg>
           </button>
        </div>
      </div>

    </div>
  );
}

import { GoogleGenAI } from "@google/genai";
import { API_KEY, SAMPLE_RATE } from "../constants";
import { LyriaSession, MusicGenerationConfig, WeightedPrompt } from "../types";

class MusicService {
  private client: GoogleGenAI;
  private session: LyriaSession | null = null;
  private audioContext: AudioContext | null = null;
  private nextStartTime: number = 0;
  private analyser: AnalyserNode | null = null;
  private gainNode: GainNode | null = null;
  private isConnected: boolean = false;

  // Track active audio sources for immediate stopping
  private activeSources: Set<AudioBufferSourceNode> = new Set();

  // Simulation State
  private isSimulation: boolean = false;
  private simulationInterval: number | null = null;
  private activeNodes: AudioNode[] = [];

  // Default config matching API defaults
  private currentConfig: MusicGenerationConfig = {
      bpm: 100,
      temperature: 1.1,
      density: 0.5,
      brightness: 0.5,
  };

  constructor() {
    this.client = new GoogleGenAI({
      apiKey: API_KEY,
      apiVersion: "v1alpha",
    });
  }

  // Initialize Audio Context
  private initAudioContext() {
    if (!this.audioContext) {
      this.audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({
        sampleRate: SAMPLE_RATE,
      });
      this.analyser = this.audioContext.createAnalyser();
      this.analyser.fftSize = 256;
      this.gainNode = this.audioContext.createGain();

      // Connect graph: Source -> Gain -> Analyser -> Destination
      this.gainNode.connect(this.analyser);
      this.analyser.connect(this.audioContext.destination);
    }
  }

  public getAnalyser(): AnalyserNode | null {
    return this.analyser;
  }

  public async connect(): Promise<void> {
    if (this.isConnected) return;
    this.initAudioContext();

    try {
      const musicClient = (this.client as any).live?.music;

      // Attempt real connection
      if (musicClient && API_KEY) {
        console.log("Connecting to Lyria model...");
        try {
            this.session = await musicClient.connect({
                model: "models/lyria-realtime-exp",
                callbacks: {
                onmessage: (message: any) => {
                    if (message.serverContent?.audioChunks) {
                    for (const chunk of message.serverContent.audioChunks) {
                        this.scheduleAudioChunk(chunk.data);
                    }
                    }
                },
                onerror: (error: any) => {
                    console.error("Music session error:", error);
                },
                onclose: () => {
                    console.log("Lyria RealTime stream closed.");
                    this.isConnected = false;
                },
                },
            });
            this.isConnected = true;
            console.log("Connected to Lyria.");
            return;
        } catch (innerError) {
             console.warn("Real Lyria connection failed, switching to Mock.", innerError);
        }
      } else {
        console.warn("No API Key or Music Client found, switching to Mock.");
      }

      // Fallback to Simulation
      this.isSimulation = true;
      this.isConnected = true;

      this.session = {
          setWeightedPrompts: async (args) => {
              console.log("[Simulation] Prompts updated:", args.weightedPrompts);
          },
          setMusicGenerationConfig: async (args) => {
              // In simulation, we merge and store the config to affect the next drone
              this.currentConfig = { ...this.currentConfig, ...args.musicGenerationConfig };
              console.log("[Simulation] Config updated:", this.currentConfig);
          },
          reset_context: async () => {
              console.log("[Simulation] Context reset");
              this.stopSimulationLoop();
              this.startSimulationLoop();
          },
          play: async () => {
              this.startSimulationLoop();
          },
          pause: async () => {
              this.stopSimulationLoop();
          },
          close: async () => {
              this.stopSimulationLoop();
              this.isConnected = false;
          }
      };

      console.log("Connected to Lyria (Simulation Mode).");

    } catch (e) {
      console.error("Fatal error in connect:", e);
      throw e;
    }
  }

  private base64ToArrayBuffer(base64: string): ArrayBuffer {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes.buffer;
  }

  private scheduleAudioChunk(base64Data: string) {
    if (!this.audioContext || !this.gainNode) return;

    const rawBuffer = this.base64ToArrayBuffer(base64Data);
    if (rawBuffer.byteLength === 0) return;

    const int16Data = new Int16Array(rawBuffer);
    const float32Data = new Float32Array(int16Data.length);

    for (let i = 0; i < int16Data.length; i++) {
      float32Data[i] = int16Data[i] / 32768.0;
    }

    const channels = 2;
    const frameCount = int16Data.length / channels;
    if (frameCount === 0) return;

    const audioBuffer = this.audioContext.createBuffer(channels, frameCount, SAMPLE_RATE);
    const leftChannel = audioBuffer.getChannelData(0);
    const rightChannel = audioBuffer.getChannelData(1);

    for (let i = 0; i < frameCount; i++) {
        leftChannel[i] = float32Data[i * 2];
        rightChannel[i] = float32Data[i * 2 + 1];
    }

    const source = this.audioContext.createBufferSource();
    source.buffer = audioBuffer;
    source.connect(this.gainNode);

    // Track active sources
    source.onended = () => {
      this.activeSources.delete(source);
    };
    this.activeSources.add(source);

    const currentTime = this.audioContext.currentTime;
    if (this.nextStartTime < currentTime) {
      this.nextStartTime = currentTime;
    }

    source.start(this.nextStartTime);
    this.nextStartTime += audioBuffer.duration;
  }

  private startSimulationLoop() {
      if (this.simulationInterval) return;

      const bpm = this.currentConfig.bpm || 100;
      // Interval for 1 bar (4 beats)
      const barDurationMs = (60 / bpm) * 4 * 1000;

      this.generateDrone(barDurationMs / 1000);
      this.simulationInterval = window.setInterval(() => {
          this.generateDrone(barDurationMs / 1000);
      }, barDurationMs);
  }

  private stopSimulationLoop() {
      if (this.simulationInterval) {
          clearInterval(this.simulationInterval);
          this.simulationInterval = null;
      }
      // Stop all scheduled buffer sources immediately
      this.activeSources.forEach(source => {
        try { source.stop(); } catch (e) {}
      });
      this.activeSources.clear();
      this.nextStartTime = 0;

      this.activeNodes.forEach(n => {
          try { (n as any).stop?.(); } catch(e){}
          n.disconnect();
      });
      this.activeNodes = [];
  }

  private generateDrone(duration: number = 4) {
      if (!this.audioContext || !this.gainNode) return;

      const oldNodes = [...this.activeNodes];
      this.activeNodes = [];

      const densityVal = this.currentConfig.density ?? 0.5;
      const brightnessVal = this.currentConfig.brightness ?? 0.5;
      const chaosVal = this.currentConfig.temperature ?? 1.1;

      const layers = Math.max(1, Math.floor(densityVal * 5));
      const baseFreq = 55;

      for (let i = 0; i < layers; i++) {
          const osc = this.audioContext.createOscillator();
          const gain = this.audioContext.createGain();
          const filter = this.audioContext.createBiquadFilter();

          const ratio = [1, 1.5, 1.33, 2, 0.5][Math.floor(Math.random() * 5)];
          osc.frequency.value = baseFreq * ratio * (i + 1);
          osc.type = i % 2 === 0 ? 'sine' : 'triangle';

          const detune = (Math.random() - 0.5) * (chaosVal * 200);
          osc.detune.value = detune;

          filter.type = 'lowpass';
          const cutoff = 200 + (brightnessVal * 1800) + (Math.random() * 200);
          filter.frequency.value = cutoff;

          const now = this.audioContext.currentTime;
          gain.gain.setValueAtTime(0, now);
          gain.gain.linearRampToValueAtTime(0.1 / layers, now + (duration * 0.25));
          gain.gain.exponentialRampToValueAtTime(0.001, now + duration);

          osc.connect(filter);
          filter.connect(gain);
          gain.connect(this.gainNode);

          osc.start(now);
          osc.stop(now + duration + 0.1);

          this.activeNodes.push(osc, gain, filter);
      }

      setTimeout(() => {
          oldNodes.forEach(n => {
            try { n.disconnect(); } catch(e) {}
          });
      }, duration * 1000 + 100);
  }

  public async play() {
    if (!this.session) return;

    if (this.audioContext?.state === 'suspended') {
      await this.audioContext.resume();
    }
    await this.session.play();
  }

  public async pause() {
    if (!this.session) return;
    await this.session.pause();
    this.stopSimulationLoop();
  }

  public async setPrompts(prompts: WeightedPrompt[]) {
    if (!this.session) return;

    const apiPrompts = prompts
      .filter(p => p.isActive)
      .map(p => ({
        text: p.text,
        weight: p.weight
      }));

    if (apiPrompts.length === 0) return;

    await this.session.setWeightedPrompts({
      weightedPrompts: apiPrompts
    });
  }

  public async updateConfig(config: Partial<MusicGenerationConfig>) {
    if (!this.session) return;

    // Explicitly handle unsetting or merging
    this.currentConfig = {
        ...this.currentConfig,
        ...config
    };

    // If a value is intentionally omitted (Auto), we should ideally not send it to the session.
    // However, since we track `this.currentConfig` to make simulation work, we send the merged version.
    await this.session.setMusicGenerationConfig({
        musicGenerationConfig: this.currentConfig
    });
  }

  public async resetContext() {
      if (this.session?.reset_context) {
          await this.session.reset_context();
      }
  }

  public setVolume(val: number) {
      if (this.gainNode) {
          this.gainNode.gain.value = val;
      }
  }
}

export const musicService = new MusicService();

import React, { useState, useEffect, useCallback, useRef } from 'react';
import PromptLayer from './components/PromptLayer';
import ControlDeck from './components/ControlDeck';
import Visualizer from './components/Visualizer';
import BpmPopup from './components/BpmPopup';
import { DEFAULT_PROMPTS, SUGGESTIONS } from './constants';
import { WeightedPrompt, MacroState, InstrumentState, MacroValue, MusicGenerationConfig } from './types';
import { musicService } from './services/musicService';

export default function App() {
  const [isPlaying, setIsPlaying] = useState(false);
  const [prompts, setPrompts] = useState<WeightedPrompt[]>(DEFAULT_PROMPTS);
  const [textInput, setTextInput] = useState('');
  const [showBpmPopup, setShowBpmPopup] = useState(false);

  const [macroState, setMacroState] = useState<MacroState>({
    density: 'auto',
    brightness: 'auto',
    chaos: 'auto',
    bpm: 'auto'
  });

  const [instrumentState, setInstrumentState] = useState<InstrumentState>({
    drums: true,
    bass: true,
    other: true
  });

  const updateApiPrompts = useCallback(async (currentPrompts: WeightedPrompt[]) => {
    if (isPlaying) {
       await musicService.setPrompts(currentPrompts);
    }
  }, [isPlaying]);

  const handlePromptWeightChange = (id: string, newWeight: number) => {
    const updated = prompts.map(p => 
      p.id === id ? { ...p, weight: newWeight } : p
    );
    setPrompts(updated);
    updateApiPrompts(updated);
  };

  const handlePromptToggle = (id: string) => {
    const updated = prompts.map(p => 
      p.id === id ? { ...p, isActive: !p.isActive } : p
    );
    setPrompts(updated);
    updateApiPrompts(updated);
  };

  const handleDeletePrompt = (id: string) => {
    const updated = prompts.filter(p => p.id !== id);
    setPrompts(updated);
    updateApiPrompts(updated);
  };

  const handleEditPrompt = (id: string, newText: string) => {
    const updated = prompts.map(p => 
      p.id === id ? { ...p, text: newText } : p
    );
    setPrompts(updated);
    updateApiPrompts(updated);
  };

  const handleAddPrompt = (text: string) => {
    if (!text) return;
    const newPrompt: WeightedPrompt = {
      id: Date.now().toString(),
      text: text,
      weight: 0.5,
      color: ['#cba6f7', '#f9e2af', '#9dffc0', '#f38ba8'][Math.floor(Math.random() * 4)],
      isActive: true
    };
    const updated = [newPrompt, ...prompts];
    setPrompts(updated);
    setTextInput('');
    updateApiPrompts(updated);
  };

  const togglePlay = async () => {
    try {
      if (!isPlaying) {
        await musicService.connect();
        await musicService.setPrompts(prompts);
        await updateConfig(); 
        await musicService.play();
      } else {
        await musicService.pause();
      }
      setIsPlaying(!isPlaying);
    } catch (e) {
      console.error("Error toggling play:", e);
      alert("Please ensure your API KEY is valid.");
    }
  };

  const updateConfigTimeout = useRef<number>(0);

  const updateConfig = async () => {
    const config: MusicGenerationConfig = {};

    // Explicitly set or omit based on 'auto'
    if (macroState.density !== 'auto') config.density = macroState.density as number;
    if (macroState.brightness !== 'auto') config.brightness = macroState.brightness as number;
    if (macroState.bpm !== 'auto') config.bpm = macroState.bpm as number;

    if (macroState.chaos !== 'auto') {
        config.temperature = (macroState.chaos as number) * 3.0;
    } else {
        config.temperature = 1.1;
    }

    config.mute_drums = !instrumentState.drums;
    config.mute_bass = !instrumentState.bass;
    config.only_bass_and_drums = !instrumentState.other;

    console.log("Applying Config to MusicService:", config);
    await musicService.updateConfig(config);
  };

  const handleMacroChange = (key: keyof MacroState, val: MacroValue) => {
      setMacroState(prev => {
          const newState = { ...prev, [key]: val };
          if (isPlaying) {
            // Debounce config updates to avoid spamming the session
            if (updateConfigTimeout.current) window.clearTimeout(updateConfigTimeout.current);
            updateConfigTimeout.current = window.setTimeout(async () => {
                await updateConfig();
                // If BPM or Chaos changed, or if we switched to Auto, we often need a context reset to hear it
                if (key === 'bpm' || key === 'chaos' || val === 'auto') {
                   await musicService.resetContext();
                }
            }, 250);
          }
          return newState;
      });
  };

  const handleApplyBpm = (val: MacroValue) => {
      handleMacroChange('bpm', val);
      setShowBpmPopup(false);
  };

  useEffect(() => {
     if (isPlaying) {
         if (updateConfigTimeout.current) window.clearTimeout(updateConfigTimeout.current);
         updateConfigTimeout.current = window.setTimeout(() => {
             updateConfig();
         }, 150);
     }
  }, [macroState.density, macroState.brightness, instrumentState]);

  return (
    <div className="h-screen w-full flex flex-col bg-black overflow-hidden font-sans">

      {/* Scrollable Content Area */}
      <div className="flex-1 overflow-y-auto px-6 pt-6 pb-40">
        <div className="w-full max-w-5xl mx-auto">
          {/* Header */}
          <div className="w-full flex justify-between items-center mb-12">
             <div className="flex items-center gap-2">
                <h1 className="text-2xl font-semibold tracking-tight">MusicFX</h1>
             </div>
             <div className="flex items-center gap-4">
                 <button className="w-8 h-8 rounded-full bg-[#222] flex items-center justify-center text-neutral-400 text-sm">?</button>
                 <button className="w-8 h-8 rounded-full bg-[#222] flex items-center justify-center text-neutral-400">⋮</button>
            </div>
          </div>

          <div className="flex flex-col items-center">
             <PromptLayer 
               prompts={prompts} 
               onUpdate={handlePromptWeightChange} 
               onToggle={handlePromptToggle} 
               onDelete={handleDeletePrompt}
               onEdit={handleEditPrompt}
             />

             {/* Add Prompt Input */}
             <div className="w-full max-w-3xl mb-8 relative group">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                    <span className="text-neutral-500 text-lg">+</span>
                </div>
                <input 
                  type="text" 
                  value={textInput}
                  onChange={(e) => setTextInput(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleAddPrompt(textInput)}
                  placeholder="Add a prompt ..."
                  className="w-full bg-[#111] rounded-2xl py-4 pl-10 pr-12 text-neutral-300 placeholder-neutral-600 focus:outline-none focus:ring-1 focus:ring-neutral-700 transition-all border border-white/5"
                />
             </div>

             {/* Suggestions */}
             <div className="w-full max-w-3xl flex flex-wrap gap-2 justify-center mb-12">
                {SUGGESTIONS.map(s => (
                   <button 
                      key={s} 
                      onClick={() => handleAddPrompt(s)}
                      className="px-4 py-2 rounded-xl bg-neutral-900 text-neutral-400 text-sm hover:bg-neutral-800 transition-colors border border-neutral-800"
                   >
                      {s}
                   </button>
                ))}
             </div>

             <ControlDeck 
                macroState={macroState}
                instrumentState={instrumentState}
                onMacroChange={handleMacroChange}
                onInstrumentToggle={(k) => setInstrumentState(p => ({ ...p, [k]: !p[k] }))}
             />
          </div>
        </div>
      </div>

      {/* Fixed Bottom Bar */}
      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 w-full max-w-5xl px-6 z-50">

        {/* BPM Popup Integration */}
        {showBpmPopup && (
            <BpmPopup 
                currentBpm={macroState.bpm} 
                onApply={handleApplyBpm} 
                onClose={() => setShowBpmPopup(false)}
            />
        )}

        <div className="bg-[#111]/90 backdrop-blur-xl rounded-[2.5rem] p-3 flex items-center gap-4 border border-white/10 shadow-[0_20px_50px_rgba(0,0,0,0.5)]">
           <button 
             onClick={togglePlay}
             className={`w-14 h-14 rounded-full flex items-center justify-center transition-all shadow-lg ${isPlaying ? 'bg-[#ff9cd6] text-black' : 'bg-[#333] text-white'}`}
           >
             {isPlaying ? (
                <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M6 4h4v16H6V4zm8 0h4v16h-4V4z"/></svg>
             ) : (
                <svg className="w-6 h-6 ml-1" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z"/></svg>
             )}
           </button>

           <div className="flex-1 h-10 bg-[#0a0a0a] rounded-xl overflow-hidden relative border border-white/5">
              <Visualizer isPlaying={isPlaying} />
              <div className="absolute top-0 left-1/2 w-px h-full bg-white/20 transform -translate-x-1/2" />
           </div>

           <div className="flex items-center gap-2">
              <button 
                onClick={() => setShowBpmPopup(!showBpmPopup)}
                className={`min-w-[64px] px-3 py-2 rounded-lg bg-[#222] transition-colors border ${showBpmPopup ? 'border-[#ffccff]' : 'border-transparent'} flex flex-col items-center justify-center`}
              >
                 <span className="text-[10px] font-bold text-neutral-400 tracking-tighter uppercase">BPM</span>
                 <span className="text-xs font-bold text-white">
                    {macroState.bpm === 'auto' ? 'Auto' : macroState.bpm}
                 </span>
              </button>
              <button className="min-w-[48px] px-3 py-2 rounded-lg bg-[#222] flex items-center justify-center">
                 <span className="text-[10px] font-bold text-neutral-400 tracking-tighter uppercase">KEY</span>
              </button>
           </div>

           <button className="w-10 h-10 rounded-full flex items-center justify-center text-neutral-500 hover:text-white transition-colors">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" /></svg>
           </button>
        </div>
      </div>

    </div>
  );
}

import { GoogleGenAI } from "@google/genai";
import { API_KEY, SAMPLE_RATE } from "../constants";
import { LyriaSession, MusicGenerationConfig, WeightedPrompt } from "../types";

class MusicService {
  private client: GoogleGenAI;
  private session: LyriaSession | null = null;
  private audioContext: AudioContext | null = null;
  private nextStartTime: number = 0;
  private analyser: AnalyserNode | null = null;
  private gainNode: GainNode | null = null;
  private isConnected: boolean = false;

  // Track active audio sources for immediate stopping
  private activeSources: Set<AudioBufferSourceNode> = new Set();

  // Simulation State
  private isSimulation: boolean = false;
  private simulationInterval: number | null = null;
  private activeNodes: AudioNode[] = [];

  // Default config matching API defaults
  private currentConfig: MusicGenerationConfig = {
      bpm: 100,
      temperature: 1.1,
      density: 0.5,
      brightness: 0.5,
  };

  constructor() {
    this.client = new GoogleGenAI({
      apiKey: API_KEY,
      apiVersion: "v1alpha",
    });
  }

  // Initialize Audio Context
  private initAudioContext() {
    if (!this.audioContext) {
      this.audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({
        sampleRate: SAMPLE_RATE,
      });
      this.analyser = this.audioContext.createAnalyser();
      this.analyser.fftSize = 256;
      this.gainNode = this.audioContext.createGain();

      // Connect graph: Source -> Gain -> Analyser -> Destination
      this.gainNode.connect(this.analyser);
      this.analyser.connect(this.audioContext.destination);
    }
  }

  public getAnalyser(): AnalyserNode | null {
    return this.analyser;
  }

  public async connect(): Promise<void> {
    if (this.isConnected) return;
    this.initAudioContext();

    try {
      const musicClient = (this.client as any).live?.music;

      // Attempt real connection
      if (musicClient && API_KEY) {
        console.log("Connecting to Lyria model...");
        try {
            this.session = await musicClient.connect({
                model: "models/lyria-realtime-exp",
                callbacks: {
                onmessage: (message: any) => {
                    if (message.serverContent?.audioChunks) {
                    for (const chunk of message.serverContent.audioChunks) {
                        this.scheduleAudioChunk(chunk.data);
                    }
                    }
                },
                onerror: (error: any) => {
                    console.error("Music session error:", error);
                },
                onclose: () => {
                    console.log("Lyria RealTime stream closed.");
                    this.isConnected = false;
                },
                },
            });
            this.isConnected = true;
            console.log("Connected to Lyria.");
            return;
        } catch (innerError) {
             console.warn("Real Lyria connection failed, switching to Mock.", innerError);
        }
      } else {
        console.warn("No API Key or Music Client found, switching to Mock.");
      }

      // Fallback to Simulation
      this.isSimulation = true;
      this.isConnected = true;

      this.session = {
          setWeightedPrompts: async (args) => {
              console.log("[Simulation] Prompts updated:", args.weightedPrompts);
          },
          setMusicGenerationConfig: async (args) => {
              // Internal update for simulation
              this.updateInternalConfig(args.musicGenerationConfig);
              console.log("[Simulation] Config updated:", this.currentConfig);
          },
          reset_context: async () => {
              console.log("[Simulation] Context reset");
              this.stopSimulationLoop();
              if (this.audioContext?.state !== 'suspended') {
                 this.startSimulationLoop();
              }
          },
          play: async () => {
              this.startSimulationLoop();
          },
          pause: async () => {
              this.stopSimulationLoop();
          },
          close: async () => {
              this.stopSimulationLoop();
              this.isConnected = false;
          }
      };

      console.log("Connected to Lyria (Simulation Mode).");

    } catch (e) {
      console.error("Fatal error in connect:", e);
      throw e;
    }
  }

  private updateInternalConfig(config: MusicGenerationConfig) {
      // Logic to merge while allowing 'undefined' to reset to simulation defaults
      if (config.bpm !== undefined) this.currentConfig.bpm = config.bpm;
      else if ('bpm' in config) this.currentConfig.bpm = 100;

      if (config.density !== undefined) this.currentConfig.density = config.density;
      else if ('density' in config) this.currentConfig.density = 0.5;

      if (config.brightness !== undefined) this.currentConfig.brightness = config.brightness;
      else if ('brightness' in config) this.currentConfig.brightness = 0.5;

      if (config.temperature !== undefined) this.currentConfig.temperature = config.temperature;
      else if ('temperature' in config) this.currentConfig.temperature = 1.1;

      this.currentConfig.mute_drums = config.mute_drums;
      this.currentConfig.mute_bass = config.mute_bass;
      this.currentConfig.only_bass_and_drums = config.only_bass_and_drums;
  }

  private base64ToArrayBuffer(base64: string): ArrayBuffer {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes.buffer;
  }

  private scheduleAudioChunk(base64Data: string) {
    if (!this.audioContext || !this.gainNode) return;

    const rawBuffer = this.base64ToArrayBuffer(base64Data);
    if (rawBuffer.byteLength === 0) return;

    const int16Data = new Int16Array(rawBuffer);
    const float32Data = new Float32Array(int16Data.length);

    for (let i = 0; i < int16Data.length; i++) {
      float32Data[i] = int16Data[i] / 32768.0;
    }

    const channels = 2;
    const frameCount = int16Data.length / channels;
    if (frameCount === 0) return;

    const audioBuffer = this.audioContext.createBuffer(channels, frameCount, SAMPLE_RATE);
    const leftChannel = audioBuffer.getChannelData(0);
    const rightChannel = audioBuffer.getChannelData(1);

    for (let i = 0; i < frameCount; i++) {
        leftChannel[i] = float32Data[i * 2];
        rightChannel[i] = float32Data[i * 2 + 1];
    }

    const source = this.audioContext.createBufferSource();
    source.buffer = audioBuffer;
    source.connect(this.gainNode);

    // Track active sources
    source.onended = () => {
      this.activeSources.delete(source);
    };
    this.activeSources.add(source);

    const currentTime = this.audioContext.currentTime;
    if (this.nextStartTime < currentTime) {
      this.nextStartTime = currentTime;
    }

    source.start(this.nextStartTime);
    this.nextStartTime += audioBuffer.duration;
  }

  private startSimulationLoop() {
      if (this.simulationInterval) return;

      const bpm = this.currentConfig.bpm || 100;
      // Interval for 1 bar (4 beats)
      const barDurationMs = (60 / bpm) * 4 * 1000;

      this.generateDrone(barDurationMs / 1000);
      this.simulationInterval = window.setInterval(() => {
          this.generateDrone(barDurationMs / 1000);
      }, barDurationMs);
  }

  private stopSimulationLoop() {
      if (this.simulationInterval) {
          clearInterval(this.simulationInterval);
          this.simulationInterval = null;
      }

      // Stop all scheduled buffer sources immediately
      this.activeSources.forEach(source => {
        try { source.stop(); } catch (e) {}
      });
      this.activeSources.clear();
      this.nextStartTime = 0;

      this.activeNodes.forEach(n => {
          try { (n as any).stop?.(); } catch(e){}
          try { n.disconnect(); } catch(e) {}
      });
      this.activeNodes = [];
  }

  private generateDrone(duration: number = 4) {
      if (!this.audioContext || !this.gainNode) return;

      const oldNodes = [...this.activeNodes];
      this.activeNodes = [];

      const densityVal = this.currentConfig.density ?? 0.5;
      const brightnessVal = this.currentConfig.brightness ?? 0.5;
      const chaosVal = this.currentConfig.temperature ?? 1.1;

      const layers = Math.max(1, Math.floor(densityVal * 5));
      const baseFreq = 55;

      for (let i = 0; i < layers; i++) {
          const osc = this.audioContext.createOscillator();
          const gain = this.audioContext.createGain();
          const filter = this.audioContext.createBiquadFilter();

          const ratio = [1, 1.5, 1.23, 2, 0.5][Math.floor(Math.random() * 5)];
          osc.frequency.value = baseFreq * ratio * (i + 1);
          osc.type = i % 2 === 0 ? 'sine' : 'triangle';

          const detune = (Math.random() - 0.5) * (chaosVal * 200);
          osc.detune.value = detune;

          filter.type = 'lowpass';
          const cutoff = 200 + (brightnessVal * 1800) + (Math.random() * 200);
          filter.frequency.value = cutoff;

          const now = this.audioContext.currentTime;
          gain.gain.setValueAtTime(0, now);
          gain.gain.linearRampToValueAtTime(0.1 / layers, now + (duration * 0.2));
          gain.gain.exponentialRampToValueAtTime(0.001, now + duration);

          osc.connect(filter);
          filter.connect(gain);
          gain.connect(this.gainNode);

          osc.start(now);
          osc.stop(now + duration + 0.1);

          this.activeNodes.push(osc, gain, filter);
      }

      setTimeout(() => {
          oldNodes.forEach(n => {
            try { n.disconnect(); } catch(e) {}
          });
      }, duration * 1000 + 100);
  }

  public async play() {
    if (!this.session) return;

    if (this.audioContext?.state === 'suspended') {
      await this.audioContext.resume();
    }
    await this.session.play();
  }

  public async pause() {
    if (!this.session) return;
    await this.session.pause();
    this.stopSimulationLoop();
  }

  public async setPrompts(prompts: WeightedPrompt[]) {
    if (!this.session) return;

    const apiPrompts = prompts
      .filter(p => p.isActive)
      .map(p => ({
        text: p.text,
        weight: p.weight
      }));

    if (apiPrompts.length === 0) return;

    await this.session.setWeightedPrompts({
      weightedPrompts: apiPrompts
    });
  }

  public async updateConfig(config: Partial<MusicGenerationConfig>) {
    if (!this.session) return;

    // Pass the delta config directly to the session
    await this.session.setMusicGenerationConfig({
        musicGenerationConfig: config
    });
  }

  public async resetContext() {
      if (this.session?.reset_context) {
          await this.session.reset_context();
      }
  }

  public setVolume(val: number) {
      if (this.gainNode) {
          this.gainNode.gain.value = val;
      }
  }
}

