import React, { useState, useEffect, useCallback, useRef } from 'react';
import PromptLayer from './components/PromptLayer';
import ControlDeck from './components/ControlDeck';
import Visualizer from './components/Visualizer';
import BpmPopup from './components/BpmPopup';
import { DEFAULT_PROMPTS, SUGGESTIONS } from './constants';
import { WeightedPrompt, MacroState, InstrumentState, MacroValue, MusicGenerationConfig } from './types';
import { musicService } from './services/musicService';

export default function App() {
  const [isPlaying, setIsPlaying] = useState(false);
  const [prompts, setPrompts] = useState<WeightedPrompt[]>(DEFAULT_PROMPTS);
  const [textInput, setTextInput] = useState('');
  const [showBpmPopup, setShowBpmPopup] = useState(false);

  const [macroState, setMacroState] = useState<MacroState>({
    density: 'auto',
    brightness: 'auto',
    chaos: 'auto',
    bpm: 'auto'
  });

  const [instrumentState, setInstrumentState] = useState<InstrumentState>({
    drums: true,
    bass: true,
    other: true
  });

  // Keep a ref to the latest state to avoid stale closures in async operations if needed,
  // though the useEffect refactoring below mostly solves this.
  const macroStateRef = useRef(macroState);
  const instrumentStateRef = useRef(instrumentState);

  useEffect(() => {
    macroStateRef.current = macroState;
    instrumentStateRef.current = instrumentState;
  }, [macroState, instrumentState]);

  const updateApiPrompts = useCallback(async (currentPrompts: WeightedPrompt[]) => {
    if (isPlaying) {
       await musicService.setPrompts(currentPrompts);
    }
  }, [isPlaying]);

  const handlePromptWeightChange = (id: string, newWeight: number) => {
    const updated = prompts.map(p => 
      p.id === id ? { ...p, weight: newWeight } : p
    );
    setPrompts(updated);
    updateApiPrompts(updated);
  };

  const handlePromptToggle = (id: string) => {
    const updated = prompts.map(p => 
      p.id === id ? { ...p, isActive: !p.isActive } : p
    );
    setPrompts(updated);
    updateApiPrompts(updated);
  };

  const handleDeletePrompt = (id: string) => {
    const updated = prompts.filter(p => p.id !== id);
    setPrompts(updated);
    updateApiPrompts(updated);
  };

  const handleEditPrompt = (id: string, newText: string) => {
    const updated = prompts.map(p => 
      p.id === id ? { ...p, text: newText } : p
    );
    setPrompts(updated);
    updateApiPrompts(updated);
  };

  const handleAddPrompt = (text: string) => {
    if (!text) return;
    const newPrompt: WeightedPrompt = {
      id: Date.now().toString(),
      text: text,
      weight: 0.5,
      color: ['#cba6f7', '#f9e2af', '#9dffc0', '#f38ba8'][Math.floor(Math.random() * 4)],
      isActive: true
    };
    const updated = [newPrompt, ...prompts];
    setPrompts(updated);
    setTextInput('');
    updateApiPrompts(updated);
  };

  const togglePlay = async () => {
    try {
      if (!isPlaying) {
        // Connect and start
        await musicService.connect();
        await musicService.setPrompts(prompts);

        // Initial config sync
        const config = generateConfig(macroStateRef.current, instrumentStateRef.current);
        await musicService.updateConfig(config);

        await musicService.play();
      } else {
        await musicService.pause();
      }
      setIsPlaying(!isPlaying);
    } catch (e) {
      console.error("Error toggling play:", e);
      alert("Please ensure your API KEY is valid.");
    }
  };

  // Helper to generate config object from state
  const generateConfig = (ms: MacroState, is: InstrumentState): MusicGenerationConfig => {
    return {
        density: ms.density === 'auto' ? 0.5 : (ms.density as number),
        brightness: ms.brightness === 'auto' ? 0.5 : (ms.brightness as number),
        bpm: ms.bpm === 'auto' ? 100 : (ms.bpm as number),
        temperature: ms.chaos === 'auto' ? 1.1 : (ms.chaos as number * 3.0),
        mute_drums: !is.drums,
        mute_bass: !is.bass,
        only_bass_and_drums: !is.other,
    };
  };

  // Track previous state to detect if we need to reset context
  const prevMacroStateRef = useRef<MacroState>(macroState);

  // Centralized Config Update Effect
  useEffect(() => {
    if (!isPlaying) {
        prevMacroStateRef.current = macroState;
        return;
    }

    const timer = setTimeout(async () => {
        const config = generateConfig(macroState, instrumentState);
        console.log("Syncing Config:", config);
        await musicService.updateConfig(config);

        // Check if we need to reset context (for structural changes)
        const prev = prevMacroStateRef.current;
        const needsReset = 
            prev.bpm !== macroState.bpm || 
            prev.chaos !== macroState.chaos ||
            (prev.bpm === 'auto' && macroState.bpm !== 'auto') || // transition from auto
            (prev.chaos === 'auto' && macroState.chaos !== 'auto'); // transition from auto

        if (needsReset) {
            console.log("Context Reset Triggered due to BPM/Chaos change");
            await musicService.resetContext();
        }

        prevMacroStateRef.current = macroState;
    }, 200); // 200ms debounce

    return () => clearTimeout(timer);
  }, [macroState, instrumentState, isPlaying]);


  const handleMacroChange = (key: keyof MacroState, val: MacroValue) => {
      setMacroState(prev => ({ ...prev, [key]: val }));
  };

  const handleApplyBpm = (val: MacroValue) => {
      handleMacroChange('bpm', val);
      setShowBpmPopup(false);
  };

  return (
    <div className="h-screen w-full flex flex-col bg-black overflow-hidden font-sans">

      {/* Scrollable Content Area */}
      <div className="flex-1 overflow-y-auto px-6 pt-6 pb-40">
        <div className="w-full max-w-5xl mx-auto">
          {/* Header */}
          <div className="w-full flex justify-between items-center mb-12">
             <div className="flex items-center gap-2">
                <h1 className="text-2xl font-semibold tracking-tight">MusicFX</h1>
             </div>
             <div className="flex items-center gap-4">
                 <button className="w-8 h-8 rounded-full bg-[#222] flex items-center justify-center text-neutral-400 text-sm">?</button>
                 <button className="w-8 h-8 rounded-full bg-[#222] flex items-center justify-center text-neutral-400">⋮</button>
            </div>
          </div>

          <div className="flex flex-col items-center">
             <PromptLayer 
               prompts={prompts} 
               onUpdate={handlePromptWeightChange} 
               onToggle={handlePromptToggle} 
               onDelete={handleDeletePrompt}
               onEdit={handleEditPrompt}
             />

             {/* Add Prompt Input */}
             <div className="w-full max-w-3xl mb-8 relative group">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                    <span className="text-neutral-500 text-lg">+</span>
                </div>
                <input 
                  type="text" 
                  value={textInput}
                  onChange={(e) => setTextInput(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleAddPrompt(textInput)}
                  placeholder="Add a prompt ..."
                  className="w-full bg-[#111] rounded-2xl py-4 pl-10 pr-12 text-neutral-300 placeholder-neutral-600 focus:outline-none focus:ring-1 focus:ring-neutral-700 transition-all border border-white/5"
                />
             </div>

             {/* Suggestions */}
             <div className="w-full max-w-3xl flex flex-wrap gap-2 justify-center mb-12">
                {SUGGESTIONS.map(s => (
                   <button 
                      key={s} 
                      onClick={() => handleAddPrompt(s)}
                      className="px-4 py-2 rounded-xl bg-neutral-900 text-neutral-400 text-sm hover:bg-neutral-800 transition-colors border border-neutral-800"
                   >
                      {s}
                   </button>
                ))}
             </div>

             <ControlDeck 
                macroState={macroState}
                instrumentState={instrumentState}
                onMacroChange={handleMacroChange}
                onInstrumentToggle={(k) => setInstrumentState(p => ({ ...p, [k]: !p[k] }))}
             />
          </div>
        </div>
      </div>

      {/* Fixed Bottom Bar */}
      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 w-full max-w-5xl px-6 z-50">

        {/* BPM Popup Integration */}
        {showBpmPopup && (
            <BpmPopup 
                currentBpm={macroState.bpm} 
                onApply={handleApplyBpm} 
                onClose={() => setShowBpmPopup(false)}
            />
        )}

        <div className="bg-[#111]/90 backdrop-blur-xl rounded-[2.5rem] p-3 flex items-center gap-4 border border-white/10 shadow-[0_20px_50px_rgba(0,0,0,0.5)]">
           <button 
             onClick={togglePlay}
             className={`w-14 h-14 rounded-full flex items-center justify-center transition-all shadow-lg ${isPlaying ? 'bg-[#ff9cd6] text-black' : 'bg-[#333] text-white'}`}
           >
             {isPlaying ? (
                <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M6 4h4v16H6V4zm8 0h4v16h-4V4z"/></svg>
             ) : (
                <svg className="w-6 h-6 ml-1" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z"/></svg>
             )}
           </button>

           <div className="flex-1 h-10 bg-[#0a0a0a] rounded-xl overflow-hidden relative border border-white/5">
              <Visualizer isPlaying={isPlaying} />
              <div className="absolute top-0 left-1/2 w-px h-full bg-white/20 transform -translate-x-1/2" />
           </div>

           <div className="flex items-center gap-2">
              <button 
                onClick={() => setShowBpmPopup(!showBpmPopup)}
                className={`min-w-[64px] px-3 py-2 rounded-lg bg-[#222] transition-colors border ${showBpmPopup ? 'border-[#ffccff]' : 'border-transparent'} flex flex-col items-center justify-center`}
              >
                 <span className="text-[10px] font-bold text-neutral-400 tracking-tighter uppercase">BPM</span>
                 <span className="text-xs font-bold text-white">
                    {macroState.bpm === 'auto' ? 'Auto' : macroState.bpm}
                 </span>
              </button>
              <button className="min-w-[48px] px-3 py-2 rounded-lg bg-[#222] flex items-center justify-center">
                 <span className="text-[10px] font-bold text-neutral-400 tracking-tighter uppercase">KEY</span>
              </button>
           </div>

           <button className="w-10 h-10 rounded-full flex items-center justify-center text-neutral-500 hover:text-white transition-colors">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" /></svg>
           </button>
        </div>
      </div>

    </div>
  );
}

import { GoogleGenAI } from "@google/genai";
import { API_KEY, SAMPLE_RATE } from "../constants";
import { LyriaSession, MusicGenerationConfig, WeightedPrompt } from "../types";

class MusicService {
  private client: GoogleGenAI;
  private session: LyriaSession | null = null;
  private audioContext: AudioContext | null = null;
  private nextStartTime: number = 0;
  private analyser: AnalyserNode | null = null;
  private gainNode: GainNode | null = null;
  private isConnected: boolean = false;

  private activeSources: Set<AudioBufferSourceNode> = new Set();
  private isSimulation: boolean = false;
  private simulationInterval: number | null = null;
  private activeNodes: AudioNode[] = [];

  private currentConfig: MusicGenerationConfig = {
      bpm: 100,
      temperature: 1.1,
      density: 0.5,
      brightness: 0.5,
  };

  constructor() {
    this.client = new GoogleGenAI({
      apiKey: API_KEY,
      apiVersion: "v1alpha",
    });
  }

  private initAudioContext() {
    if (!this.audioContext) {
      this.audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({
        sampleRate: SAMPLE_RATE,
      });
      this.analyser = this.audioContext.createAnalyser();
      this.analyser.fftSize = 256;
      this.gainNode = this.audioContext.createGain();
      this.gainNode.connect(this.analyser);
      this.analyser.connect(this.audioContext.destination);
    }
  }

  public getAnalyser(): AnalyserNode | null {
    return this.analyser;
  }

  public async connect(): Promise<void> {
    if (this.isConnected) return;
    this.initAudioContext();

    try {
      const musicClient = (this.client as any).live?.music;

      if (musicClient && API_KEY) {
        console.log("Connecting to Lyria model...");
        try {
            this.session = await musicClient.connect({
                model: "models/lyria-realtime-exp",
                callbacks: {
                  onmessage: (message: any) => {
                      if (message.serverContent?.audioChunks) {
                        for (const chunk of message.serverContent.audioChunks) {
                            this.scheduleAudioChunk(chunk.data);
                        }
                      }
                  },
                  onerror: (error: any) => console.error("Music session error:", error),
                  onclose: () => {
                      console.log("Lyria RealTime stream closed.");
                      this.isConnected = false;
                  },
                },
            });
            this.isConnected = true;
            return;
        } catch (innerError) {
             console.warn("Real Lyria connection failed, using Simulation.", innerError);
        }
      }

      this.isSimulation = true;
      this.isConnected = true;
      this.session = {
          setWeightedPrompts: async (args) => console.log("[Sim] Prompts:", args.weightedPrompts),
          setMusicGenerationConfig: async (args) => {
              this.updateInternalConfig(args.musicGenerationConfig);
          },
          reset_context: async () => {
              this.stopSimulationLoop();
              if (this.audioContext?.state !== 'suspended') this.startSimulationLoop();
          },
          play: async () => this.startSimulationLoop(),
          pause: async () => this.stopSimulationLoop(),
          close: async () => {
              this.stopSimulationLoop();
              this.isConnected = false;
          }
      };
    } catch (e) {
      console.error("Connection error:", e);
      throw e;
    }
  }

  private updateInternalConfig(config: MusicGenerationConfig) {
      // Explicitly merge incoming config into our tracking object
      if (config.bpm !== undefined) this.currentConfig.bpm = config.bpm;
      if (config.density !== undefined) this.currentConfig.density = config.density;
      if (config.brightness !== undefined) this.currentConfig.brightness = config.brightness;
      if (config.temperature !== undefined) this.currentConfig.temperature = config.temperature;

      this.currentConfig.mute_drums = config.mute_drums;
      this.currentConfig.mute_bass = config.mute_bass;
      this.currentConfig.only_bass_and_drums = config.only_bass_and_drums;

      console.log("[Sim] Internal Config Updated. BPM:", this.currentConfig.bpm);
  }

  private scheduleAudioChunk(base64Data: string) {
    if (!this.audioContext || !this.gainNode) return;
    const rawBuffer = this.base64ToArrayBuffer(base64Data);
    const int16Data = new Int16Array(rawBuffer);
    const float32Data = new Float32Array(int16Data.length);
    for (let i = 0; i < int16Data.length; i++) float32Data[i] = int16Data[i] / 32768.0;

    const channels = 2;
    const frameCount = int16Data.length / channels;
    const audioBuffer = this.audioContext.createBuffer(channels, frameCount, SAMPLE_RATE);
    audioBuffer.getChannelData(0).set(float32Data.filter((_, i) => i % 2 === 0));
    audioBuffer.getChannelData(1).set(float32Data.filter((_, i) => i % 2 !== 0));

    const source = this.audioContext.createBufferSource();
    source.buffer = audioBuffer;
    source.connect(this.gainNode);
    source.onended = () => this.activeSources.delete(source);
    this.activeSources.add(source);

    this.nextStartTime = Math.max(this.nextStartTime, this.audioContext.currentTime);
    source.start(this.nextStartTime);
    this.nextStartTime += audioBuffer.duration;
  }

  private base64ToArrayBuffer(base64: string): ArrayBuffer {
    const binary = window.atob(base64);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
    return bytes.buffer;
  }

  private startSimulationLoop() {
      if (this.simulationInterval) return;

      const run = () => {
          const bpm = this.currentConfig.bpm || 100;
          const barDurationMs = (60 / bpm) * 4 * 1000;
          this.generateDrone(barDurationMs / 1000);
          this.simulationInterval = window.setTimeout(run, barDurationMs);
      };
      run();
  }

  private stopSimulationLoop() {
      if (this.simulationInterval) {
          clearTimeout(this.simulationInterval);
          this.simulationInterval = null;
      }
      this.activeSources.forEach(s => { try { s.stop(); } catch(e) {} });
      this.activeSources.clear();
      this.activeNodes.forEach(n => {
          try { (n as any).stop?.(); } catch(e){}
          try { n.disconnect(); } catch(e) {}
      });
      this.activeNodes = [];
  }

  private generateDrone(duration: number) {
      if (!this.audioContext || !this.gainNode) return;
      const now = this.audioContext.currentTime;

      // Pulse / Kick (to visualize BPM changes clearly)
      const kick = this.audioContext.createOscillator();
      const kickGain = this.audioContext.createGain();
      kick.frequency.setValueAtTime(150, now);
      kick.frequency.exponentialRampToValueAtTime(0.01, now + 0.1);
      kickGain.gain.setValueAtTime(0.3, now);
      kickGain.gain.exponentialRampToValueAtTime(0.01, now + 0.1);
      kick.connect(kickGain);
      kickGain.connect(this.gainNode);
      kick.start(now);
      kick.stop(now + 0.15);

      // Drone Layers
      const layers = Math.max(1, Math.floor((this.currentConfig.density || 0.5) * 5));
      for (let i = 0; i < layers; i++) {
          const osc = this.audioContext.createOscillator();
          const g = this.audioContext.createGain();
          const f = this.audioContext.createBiquadFilter();

          osc.frequency.value = 55 * (i + 1) * (i % 2 === 0 ? 1 : 1.5);
          osc.detune.value = (Math.random() - 0.5) * (this.currentConfig.temperature || 1) * 100;
          f.frequency.value = 200 + (this.currentConfig.brightness || 0.5) * 2000;

          g.gain.setValueAtTime(0, now);
          g.gain.linearRampToValueAtTime(0.05 / layers, now + duration * 0.2);
          g.gain.exponentialRampToValueAtTime(0.001, now + duration);

          osc.connect(f);
          f.connect(g);
          g.connect(this.gainNode);
          osc.start(now);
          osc.stop(now + duration + 0.1);
          this.activeNodes.push(osc, g, f);
      }
  }

  public async play() {
    if (!this.session) return;
    if (this.audioContext?.state === 'suspended') await this.audioContext.resume();
    await this.session.play();
  }

  public async pause() {
    if (!this.session) return;
    await this.session.pause();
    this.stopSimulationLoop();
  }

  public async setPrompts(prompts: WeightedPrompt[]) {
    if (!this.session) return;
    const active = prompts.filter(p => p.isActive).map(p => ({ text: p.text, weight: p.weight }));
    if (active.length > 0) await this.session.setWeightedPrompts({ weightedPrompts: active });
  }

  public async updateConfig(config: Partial<MusicGenerationConfig>) {
    if (!this.session) return;
