                 const up = prompts.filter(p => p.id !== id);
                 setPrompts(up); updateApiPrompts(up);
               }}
               onEdit={(id, t) => {
                 const up = prompts.map(p => p.id === id ? {...p, text: t} : p);
                 setPrompts(up); updateApiPrompts(up);
               }}
             />

