                />
             </div>

             <div className="w-full max-w-3xl flex flex-wrap gap-2 justify-center mb-12">
                {SUGGESTIONS.map(s => (
                   <button key={s} onClick={() => {
                     const np = { id: Date.now().toString(), text: s, weight: 0.5, color: '#f9e2af', isActive: true };
