import React, { useEffect, useRef } from 'react';
import { musicService } from '../services/musicService';

interface VisualizerProps {
  isPlaying: boolean;
}

const Visualizer: React.FC<VisualizerProps> = ({ isPlaying }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationRef = useRef<number | null>(null);

  // Stores history of [min, max] pairs for the waveform envelope
  const historyRef = useRef<Float32Array | null>(null);
  const writeIndexRef = useRef(0);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Initialize history buffer to match canvas width
    // Storing 2 values per pixel column: min and max
    if (!historyRef.current || historyRef.current.length !== canvas.width * 2) {
        historyRef.current = new Float32Array(canvas.width * 2);
        // Fill with silence (0)
        historyRef.current.fill(0);
        writeIndexRef.current = 0;
    }

    const analyser = musicService.getAnalyser();
    const bufferLength = analyser ? analyser.frequencyBinCount : 0;
    const dataArray = new Uint8Array(bufferLength);

    const draw = () => {
      // 1. Acquire Data
      let min = 0;
      let max = 0;

      if (analyser && isPlaying) {
        analyser.getByteTimeDomainData(dataArray);

        // Calculate min/max for the current frame to define the envelope
        // dataArray is 0-255, 128 is silence. Normalize to -1 to 1.
        let localMin = 1.0;
        let localMax = -1.0;

        for (let i = 0; i < bufferLength; i++) {
            const v = (dataArray[i] - 128) / 128.0;
            if (v < localMin) localMin = v;
            if (v > localMax) localMax = v;
        }

        // Add some decay or smoothing if silence to prevent flickering line
        if (localMax < localMin) { // Should not happen unless empty buffer
             localMin = 0; localMax = 0; 
        }
        min = localMin;
        max = localMax;
      }

      // 2. Update History (Scroll Logic)
      // We essentially want to push (min, max) to the end and shift everything left.
      // But shifting a large typed array is expensive. 
      // Instead, we can shift the drawing or use a circular buffer.
      // For this visualization, simple array shift is O(N) but N is small (e.g. 1000). It's fine.
      const history = historyRef.current!;

      // Shift left by 2 (one pair)
      history.set(history.subarray(2), 0);

      // Insert new data at the end
      const lastIdx = history.length - 2;
      history[lastIdx] = min;
      history[lastIdx + 1] = max;

      // 3. Render
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      ctx.lineWidth = 1;
      ctx.strokeStyle = '#e2e8f0'; // Light gray
      ctx.beginPath();

      const centerY = canvas.height / 2;
      const heightScale = canvas.height / 2;

      // Draw vertical lines for each column in history
      for (let x = 0; x < canvas.width; x++) {
          const idx = x * 2;
          const valMin = history[idx];
          const valMax = history[idx + 1];

          // Optimization: Only draw if there is sound
          if (Math.abs(valMin) > 0.01 || Math.abs(valMax) > 0.01) {
             ctx.moveTo(x, centerY + valMin * heightScale);
             ctx.lineTo(x, centerY + valMax * heightScale);
          } else {
             // Draw a flat line dot? Or just skip for cleaner look.
             // Drawing a continuous center line looks better
             ctx.moveTo(x, centerY);
             ctx.lineTo(x + 1, centerY);
          }
      }

      ctx.stroke();

      animationRef.current = requestAnimationFrame(draw);
    };

    animationRef.current = requestAnimationFrame(draw);

    return () => {
      if (animationRef.current !== null) cancelAnimationFrame(animationRef.current);
    };
  }, [isPlaying]);

  return (
    <canvas 
      ref={canvasRef} 
      width={800} // Higher internal resolution
      height={80} 
      className="w-full h-full opacity-60"
    />
  );
};

export default Visualizer;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import PromptLayer from './components/PromptLayer';
import ControlDeck from './components/ControlDeck';
import Visualizer from './components/Visualizer';
import BpmPopup from './components/BpmPopup';
import KeyPopup from './components/KeyPopup';
import { DEFAULT_PROMPTS, SUGGESTIONS } from './constants';
import { WeightedPrompt, MacroState, InstrumentState, MacroValue, MusicGenerationConfig } from './types';
import { musicService } from './services/musicService';

export default function App() {
  const [isPlaying, setIsPlaying] = useState(false);
  const [prompts, setPrompts] = useState<WeightedPrompt[]>(DEFAULT_PROMPTS);
  const [textInput, setTextInput] = useState('');
  const [showBpmPopup, setShowBpmPopup] = useState(false);
  const [showKeyPopup, setShowKeyPopup] = useState(false);

  const [macroState, setMacroState] = useState<MacroState>({
    density: 'auto',
    brightness: 'auto',
    chaos: 'auto',
    bpm: 'auto',
    key: 'auto'
  });

  const [instrumentState, setInstrumentState] = useState<InstrumentState>({
    drums: true,
    bass: true,
    other: true
  });

  const macroStateRef = useRef(macroState);
  useEffect(() => { macroStateRef.current = macroState; }, [macroState]);

  const updateApiPrompts = useCallback(async (currentPrompts: WeightedPrompt[]) => {
    if (isPlaying) await musicService.setPrompts(currentPrompts);
  }, [isPlaying]);

  const formatKeyForApi = (keyStr: string): string | undefined => {
    if (keyStr === 'auto') return undefined;

    // Expected format from UI: "Root Mode" e.g. "C Major", "F# Minor", "Bb Major"
    const parts = keyStr.split(' ');
    if (parts.length !== 2) return undefined;

    const root = parts[0];
    const mode = parts[1]; // "Major" or "Minor"

    // 1. Map input roots to semitone indices (0 = C, 1 = C#/Db, etc.)
    const rootIndices: {[key: string]: number} = {
        'C': 0, 'C#': 1, 'Db': 1,
        'D': 2,
        'D#': 3, 'Eb': 3,
        'E': 4,
        'F': 5,
        'F#': 6, 'Gb': 6,
        'G': 7,
        'G#': 8, 'Ab': 8,
        'A': 9,
        'A#': 10, 'Bb': 10,
        'B': 11
    };

    let index = rootIndices[root];
    if (index === undefined) return undefined;

    // 2. If Minor, shift to relative Major (+3 semitones)
    // e.g. A Minor (9) + 3 = 12 -> 0 (C Major)
    if (mode === 'Minor') {
        index = (index + 3) % 12;
    }

    // 3. Map Major Key Index to the specific API Enum
    const apiEnums = [
        'C_MAJOR_A_MINOR',               // 0: C
        'D_FLAT_MAJOR_B_FLAT_MINOR',     // 1: Db
        'D_MAJOR_B_MINOR',               // 2: D
        'E_FLAT_MAJOR_C_MINOR',          // 3: Eb
        'E_MAJOR_D_FLAT_MINOR',          // 4: E
        'F_MAJOR_D_MINOR',               // 5: F
        'G_FLAT_MAJOR_E_FLAT_MINOR',     // 6: Gb
        'G_MAJOR_E_MINOR',               // 7: G
        'A_FLAT_MAJOR_F_MINOR',          // 8: Ab
        'A_MAJOR_G_FLAT_MINOR',          // 9: A
        'B_FLAT_MAJOR_G_MINOR',          // 10: Bb
        'B_MAJOR_A_FLAT_MINOR'           // 11: B
    ];

    return apiEnums[index];
  };

  const generateConfig = (ms: MacroState, is: InstrumentState): MusicGenerationConfig => {
      const config: MusicGenerationConfig = {
        density: ms.density === 'auto' ? 0.5 : (ms.density as number),
        brightness: ms.brightness === 'auto' ? 0.5 : (ms.brightness as number),
        bpm: ms.bpm === 'auto' ? 100 : (ms.bpm as number),
        temperature: ms.chaos === 'auto' ? 1.1 : (ms.chaos as number * 3.0),
        mute_drums: !is.drums,
        mute_bass: !is.bass,
        only_bass_and_drums: !is.other,
      };

      const apiScale = formatKeyForApi(ms.key as string);
      if (apiScale) {
          config.scale = apiScale;
      }

      return config;
  };

  const prevMacroStateRef = useRef<MacroState>(macroState);

  useEffect(() => {
    if (!isPlaying) {
        prevMacroStateRef.current = macroState;
        return;
    }

    const timer = setTimeout(async () => {
        // ALWAYS send the FULL configuration. 
        const config = generateConfig(macroState, instrumentState);

        const prev = prevMacroStateRef.current;
        const bpmChanged = prev.bpm !== macroState.bpm;
        const keyChanged = prev.key !== macroState.key;
        const chaosChanged = prev.chaos !== macroState.chaos;

        // Structural changes: Cut audio immediately and restart
        if (bpmChanged || keyChanged) {
            console.log("Structure changed (BPM/Key). Cutting audio and resetting...");
            await musicService.stopAndClear();
            await musicService.updateConfig(config);
            await musicService.resetContext();
            await musicService.play();
        } else if (chaosChanged) {
             // Chaos change might also benefit from a reset but maybe softer? 
             // User only requested strict restart for BPM/Key, but chaos usually implies re-seeding.
             // We'll treat chaos similarly for consistency in "remaking" the track.
            await musicService.updateConfig(config);
            await musicService.resetContext(); 
        } else {
            // Soft update (instruments, density, brightness)
             console.log("Applying soft config update:", config);
             await musicService.updateConfig(config);
        }

        prevMacroStateRef.current = macroState;
    }, 150);

    return () => clearTimeout(timer);
  }, [macroState, instrumentState, isPlaying]);

  const togglePlay = async () => {
    try {
      if (!isPlaying) {
        await musicService.connect();
        await musicService.setPrompts(prompts);

        const config = generateConfig(macroState, instrumentState);
        await musicService.updateConfig(config);

        await musicService.play();
      } else {
        await musicService.pause();
      }
      setIsPlaying(!isPlaying);
    } catch (e) {
      console.error("Play error:", e);
    }
  };

  const handleMacroChange = (key: keyof MacroState, val: MacroValue | string) => {
      setMacroState(prev => ({ ...prev, [key]: val }));
  };

  return (
    <div className="h-screen w-full flex flex-col bg-black overflow-hidden font-sans">
      <div className="flex-1 overflow-y-auto px-6 pt-6 pb-40">
        <div className="w-full max-w-5xl mx-auto">
          <div className="w-full flex justify-between items-center mb-12">
             <h1 className="text-2xl font-semibold tracking-tight">MusicFX</h1>
             <div className="flex gap-4">
                 <button className="w-8 h-8 rounded-full bg-[#222] text-neutral-400">?</button>
                 <button className="w-8 h-8 rounded-full bg-[#222] text-neutral-400">⋮</button>
            </div>
          </div>

          <div className="flex flex-col items-center">
             <PromptLayer 
               prompts={prompts} 
               onUpdate={(id, w) => {
                 const up = prompts.map(p => p.id === id ? {...p, weight: w} : p);
                 setPrompts(up); updateApiPrompts(up);
               }} 
               onToggle={(id) => {
                 const up = prompts.map(p => p.id === id ? {...p, isActive: !p.isActive} : p);
                 setPrompts(up); updateApiPrompts(up);
               }} 
               onDelete={(id) => {
                 const up = prompts.filter(p => p.id !== id);
                 setPrompts(up); updateApiPrompts(up);
               }}
               onEdit={(id, t) => {
                 const up = prompts.map(p => p.id === id ? {...p, text: t} : p);
                 setPrompts(up); updateApiPrompts(up);
               }}
             />

             <div className="w-full max-w-3xl mb-8 relative">
                <input 
                  type="text" 
                  value={textInput}
                  onChange={(e) => setTextInput(e.target.value)}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' && textInput) {
                      const np = { id: Date.now().toString(), text: textInput, weight: 0.5, color: '#cba6f7', isActive: true };
                      const up = [np, ...prompts];
                      setPrompts(up); setTextInput(''); updateApiPrompts(up);
                    }
                  }}
                  placeholder="Add a prompt ..."
                  className="w-full bg-[#111] rounded-2xl py-4 pl-10 pr-12 text-neutral-300 border border-white/5"
                />
             </div>

             <div className="w-full max-w-3xl flex flex-wrap gap-2 justify-center mb-12">
                {SUGGESTIONS.map(s => (
                   <button key={s} onClick={() => {
                     const np = { id: Date.now().toString(), text: s, weight: 0.5, color: '#f9e2af', isActive: true };
                     const up = [np, ...prompts];
                     setPrompts(up); updateApiPrompts(up);
                   }} className="px-4 py-2 rounded-xl bg-neutral-900 text-neutral-400 text-sm border border-neutral-800 hover:bg-neutral-800 transition-colors">
                      {s}
                   </button>
                ))}
             </div>

             <ControlDeck 
                macroState={macroState}
                instrumentState={instrumentState}
                onMacroChange={handleMacroChange}
                onInstrumentToggle={(k) => setInstrumentState(p => ({ ...p, [k]: !p[k] }))}
             />
          </div>
        </div>
      </div>

      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 w-full max-w-5xl px-6 z-50">
        {showBpmPopup && (
            <BpmPopup 
                currentBpm={macroState.bpm} 
                onApply={(v) => { handleMacroChange('bpm', v); setShowBpmPopup(false); }} 
                onClose={() => setShowBpmPopup(false)}
            />
        )}

        {showKeyPopup && (
            <KeyPopup
                currentKey={macroState.key}
                onApply={(v) => { handleMacroChange('key', v); setShowKeyPopup(false); }}
                onClose={() => setShowKeyPopup(false)}
            />
        )}

        <div className="bg-[#111]/90 backdrop-blur-xl rounded-[2.5rem] p-3 flex items-center gap-4 border border-white/10 shadow-2xl">
           <button onClick={togglePlay} className={`w-14 h-14 rounded-full flex items-center justify-center transition-all ${isPlaying ? 'bg-[#ff9cd6] text-black' : 'bg-[#333] text-white'}`}>
             {isPlaying ? <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M6 4h4v16H6V4zm8 0h4v16h-4V4z"/></svg> : <svg className="w-6 h-6 ml-1" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z"/></svg>}
           </button>

           <div className="flex-1 h-10 bg-[#0a0a0a] rounded-xl overflow-hidden relative border border-white/5">
              <Visualizer isPlaying={isPlaying} />
              <div className="absolute top-0 left-1/2 w-px h-full bg-white/20 transform -translate-x-1/2" />
           </div>

           <div className="flex items-center gap-2">
              <button 
                onClick={() => { setShowKeyPopup(false); setShowBpmPopup(!showBpmPopup); }} 
                className={`min-w-[64px] px-3 py-2 rounded-lg bg-[#222] border ${showBpmPopup ? 'border-[#ffccff]' : 'border-transparent'} flex flex-col items-center transition-colors`}
              >
                 <span className="text-[10px] font-bold text-neutral-500 uppercase">BPM</span>
                 <span className="text-xs font-bold text-white">{macroState.bpm === 'auto' ? 'Auto' : macroState.bpm}</span>
              </button>

              <button 
                onClick={() => { setShowBpmPopup(false); setShowKeyPopup(!showKeyPopup); }}
                className={`min-w-[48px] px-3 py-2 rounded-lg bg-[#222] border ${showKeyPopup ? 'border-[#ffccff]' : 'border-transparent'} flex flex-col items-center transition-colors`}
              >
                 <span className="text-[10px] font-bold text-neutral-500 uppercase">KEY</span>
                 <span className="text-xs font-bold text-white whitespace-nowrap overflow-hidden text-ellipsis max-w-[50px]">
                    {macroState.key === 'auto' ? 'Auto' : (macroState.key as string).replace(' ', '')}
                 </span>
              </button>
           </div>

           <button className="w-10 h-10 rounded-full flex items-center justify-center text-neutral-500 hover:text-white">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" /></svg>
           </button>
        </div>
      </div>
    </div>
  );
}

export interface WeightedPrompt {
  id: string;
  text: string;
  weight: number;
  color: string;
  isActive: boolean;
}

export interface MusicGenerationConfig {
  bpm: number;
  scale?: string; // e.g. "C_MAJOR", "A_MINOR"
  temperature: number;
  density: number; // 0.0 to 1.0
  brightness: number; // 0.0 to 1.0
  mute_drums: boolean;
  mute_bass: boolean;
  only_bass_and_drums: boolean;
}

// Defining the shape of the experimental Lyria API based on user request
export interface LyriaSession {
  setWeightedPrompts: (args: { weightedPrompts: { text: string; weight: number }[] }) => Promise<void>;
  setMusicGenerationConfig: (args: { musicGenerationConfig: MusicGenerationConfig }) => Promise<void>;
  // Support both potential naming conventions for the alpha SDK
  reset_context?: () => Promise<void>;
  resetContext?: () => Promise<void>;
  play: () => Promise<void>;
  pause: () => Promise<void>; 
  close: () => Promise<void>;
}

export type MacroValue = number | 'auto';

export interface MacroState {
  density: MacroValue;
  brightness: MacroValue;
  chaos: MacroValue;
  bpm: MacroValue;
  key: string | 'auto';
}

export interface InstrumentState {
  drums: boolean;
  bass: boolean;
  other: boolean;
}

export interface VisualizerChunk {
  id: string;
  data: Float32Array; // Interleaved Min/Max values
  startTime: number;
  duration: number;
  receivedAt: number; // For animation
}

export interface VisualizerEvent {
  type: 'chunk' | 'reset';
  chunk?: VisualizerChunk;
}

import { GoogleGenAI } from "@google/genai";
import { API_KEY, SAMPLE_RATE } from "../constants";
import { LyriaSession, MusicGenerationConfig, WeightedPrompt, VisualizerEvent, VisualizerChunk } from "../types";

class MusicService {
  private client: GoogleGenAI;
  private session: LyriaSession | null = null;
  private audioContext: AudioContext | null = null;
  private nextStartTime: number = 0;
  private analyser: AnalyserNode | null = null;
  private gainNode: GainNode | null = null;
  private isConnected: boolean = false;

  private activeSources: Set<AudioBufferSourceNode> = new Set();
  private isSimulation: boolean = false;
  private simulationInterval: number | null = null;
  private activeNodes: AudioNode[] = [];

  private listeners: Set<(event: VisualizerEvent) => void> = new Set();

  private currentConfig: MusicGenerationConfig = {
      bpm: 100,
      scale: 'C_MAJOR_A_MINOR',
      temperature: 1.1,
      density: 0.5,
      brightness: 0.5,
      mute_drums: false,
      mute_bass: false,
      only_bass_and_drums: false
  };

  constructor() {
    this.client = new GoogleGenAI({
      apiKey: API_KEY,
      apiVersion: "v1alpha",
    });
  }

  private initAudioContext() {
    if (!this.audioContext) {
      this.audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({
        sampleRate: SAMPLE_RATE,
      });
      this.analyser = this.audioContext.createAnalyser();
      this.analyser.fftSize = 2048; 
      this.gainNode = this.audioContext.createGain();
      this.gainNode.connect(this.analyser);
      this.analyser.connect(this.audioContext.destination);
    }
  }

  public getAnalyser(): AnalyserNode | null {
    return this.analyser;
  }

  public getCurrentTime(): number {
      return this.audioContext?.currentTime || 0;
  }

  public subscribe(callback: (event: VisualizerEvent) => void): () => void {
      this.listeners.add(callback);
      return () => this.listeners.delete(callback);
  }

  private emit(event: VisualizerEvent) {
      this.listeners.forEach(cb => cb(event));
  }

  public async connect(): Promise<void> {
    if (this.isConnected) return;
    this.initAudioContext();

    try {
      const musicClient = (this.client as any).live?.music;

      if (musicClient && API_KEY) {
        console.log("Connecting to Lyria model...");
        try {
            this.session = await musicClient.connect({
                model: "models/lyria-realtime-exp",
                callbacks: {
                  onmessage: (message: any) => {
                      if (message.serverContent?.audioChunks) {
                        for (const chunk of message.serverContent.audioChunks) {
                            this.scheduleAudioChunk(chunk.data);
                        }
                      }
                  },
                  onerror: (error: any) => console.error("Music session error:", error),
                  onclose: () => {
                      console.log("Lyria RealTime stream closed.");
                      this.isConnected = false;
                  },
                },
            });
            this.isConnected = true;
            return;
        } catch (innerError) {
             console.warn("Real Lyria connection failed, using Simulation.", innerError);
        }
      }

      this.isSimulation = true;
      this.isConnected = true;
      this.session = {
          setWeightedPrompts: async (args) => console.log("[Sim] Prompts:", args.weightedPrompts),
          setMusicGenerationConfig: async (args) => {
              this.currentConfig = args.musicGenerationConfig;
              console.log("[Sim] Config Full Update:", this.currentConfig);
          },
          reset_context: async () => {
              console.log("[Sim] Reset Context - Restarting Loop");
              this.stopSimulationLoop();
              if (this.audioContext?.state !== 'suspended') this.startSimulationLoop();
          },
          play: async () => this.startSimulationLoop(),
          pause: async () => this.stopSimulationLoop(),
          close: async () => {
              this.stopSimulationLoop();
              this.isConnected = false;
          }
      };
    } catch (e) {
      console.error("Connection error:", e);
      throw e;
    }
  }

  private scheduleAudioChunk(base64Data: string) {
    if (!this.audioContext || !this.gainNode) return;
    const rawBuffer = this.base64ToArrayBuffer(base64Data);
    const int16Data = new Int16Array(rawBuffer);
    const float32Data = new Float32Array(int16Data.length);
    for (let i = 0; i < int16Data.length; i++) float32Data[i] = int16Data[i] / 32768.0;

    const channels = 2;
    const frameCount = int16Data.length / channels;
    const audioBuffer = this.audioContext.createBuffer(channels, frameCount, SAMPLE_RATE);

    // We only visually process the first channel (mono mixdown for vis)
    const channel0 = float32Data.filter((_, i) => i % 2 === 0);
    audioBuffer.getChannelData(0).set(channel0);
    audioBuffer.getChannelData(1).set(float32Data.filter((_, i) => i % 2 !== 0));

    const source = this.audioContext.createBufferSource();
    source.buffer = audioBuffer;
    source.connect(this.gainNode);
    source.onended = () => this.activeSources.delete(source);
    this.activeSources.add(source);

    // Ensure seamless playback
    this.nextStartTime = Math.max(this.nextStartTime, this.audioContext.currentTime);
    const chunkStartTime = this.nextStartTime;
    source.start(this.nextStartTime);
    this.nextStartTime += audioBuffer.duration;

    // --- VISUALIZER PROCESSING ---
    // Downsample the buffer to ~200 samples per second equivalent (envelope)
    // for efficient rendering.
    const envelope = this.extractEnvelope(channel0, 256); // 256 step = ~170 points per second at 44.1k

    this.emit({
        type: 'chunk',
        chunk: {
            id: Math.random().toString(36).substring(7),
            data: envelope,
            startTime: chunkStartTime,
            duration: audioBuffer.duration,
            receivedAt: Date.now()
        }
    });
  }

  private extractEnvelope(data: Float32Array, step: number): Float32Array {
      const len = data.length;
      const result = new Float32Array(Math.ceil(len / step) * 2);
      let idx = 0;
      for (let i = 0; i < len; i += step) {
          let min = 1.0;
          let max = -1.0;
          const end = Math.min(len, i + step);
          for (let j = i; j < end; j++) {
              const v = data[j];
              if (v < min) min = v;
              if (v > max) max = v;
          }
          // If silence
          if (max < min) { min = 0; max = 0; }

          result[idx++] = min;
          result[idx++] = max;
      }
      return result;
  }

  private base64ToArrayBuffer(base64: string): ArrayBuffer {
    const binary = window.atob(base64);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
    return bytes.buffer;
  }

  private startSimulationLoop() {
      if (this.simulationInterval) return;

      const run = () => {
          const bpm = this.currentConfig.bpm || 100;
          const barDurationMs = (60 / bpm) * 4 * 1000;
          this.generateDrone(barDurationMs / 1000);
          this.simulationInterval = window.setTimeout(run, barDurationMs);
      };
      run();
  }

  private stopSimulationLoop() {
      if (this.simulationInterval) {
          clearTimeout(this.simulationInterval);
          this.simulationInterval = null;
      }
      this.activeSources.forEach(s => { try { s.stop(); } catch(e) {} });
      this.activeSources.clear();
      this.activeNodes.forEach(n => {
          try { (n as any).stop?.(); } catch(e){}
          try { n.disconnect(); } catch(e) {}
      });
      this.activeNodes = [];
  }

  // Immediately stops all audio and resets the scheduling cursor
  public async stopAndClear() {
      if (this.isSimulation) {
          this.stopSimulationLoop();
      }

      // Stop all scheduled sources
      this.activeSources.forEach(source => {
          try { source.stop(); } catch(e) {}
      });
      this.activeSources.clear();

      if (this.audioContext) {
          // Reset cursor to slightly in the future to allow new chunks to schedule cleanly
          this.nextStartTime = this.audioContext.currentTime + 0.1; 
      }

      // Notify Visualizer to clear
      this.emit({ type: 'reset' });
  }

  private generateDrone(duration: number) {
      if (!this.audioContext || !this.gainNode) return;
      const now = this.audioContext.currentTime;

      // Calculate Pitch based on Scale (Simulation Only)
      // Base C = ~65.41Hz
      let baseFreq = 65.41; 
      const scaleStr = this.currentConfig.scale || 'C_MAJOR_A_MINOR';

      const roots: {[key:string]: number} = {
          'C': 0, 
          'C_SHARP': 1, 'D_FLAT': 1,
          'D': 2, 
          'E_FLAT': 3, 
          'E': 4, 
          'F': 5,
          'F_SHARP': 6, 'G_FLAT': 6,
          'G': 7, 
          'A_FLAT': 8, 
          'A': 9, 
          'B_FLAT': 10, 
          'B': 11
      };

      let rootName = 'C';
      let longestMatch = '';
      for(const k of Object.keys(roots)) {
          if(scaleStr.startsWith(k)) {
            if (k.length > longestMatch.length) longestMatch = k;
          }
      }
      if (longestMatch) rootName = longestMatch;

      const semitones = roots[rootName] || 0;
      baseFreq = baseFreq * Math.pow(2, semitones / 12);

      // Simulation of a chunk for visualization
      // We generate synthetic envelope data for the sim
      // duration in seconds. 256 step size means ~172 chunks per sec.
      const points = Math.ceil(duration * 172);
      const fakeEnvelope = new Float32Array(points * 2);
      for(let i=0; i<points; i++) {
          const amp = Math.random() * 0.5;
          fakeEnvelope[i*2] = -amp;
          fakeEnvelope[i*2+1] = amp;
      }

      // Schedule real audio (SIM)
      // Pulse / Kick 
      const kick = this.audioContext.createOscillator();
      const kickGain = this.audioContext.createGain();
      kick.frequency.setValueAtTime(150, now);
      kick.frequency.exponentialRampToValueAtTime(0.01, now + 0.1);
      kickGain.gain.setValueAtTime(0.3, now);
      kickGain.gain.exponentialRampToValueAtTime(0.01, now + 0.1);
      kick.connect(kickGain);
      kickGain.connect(this.gainNode);
      kick.start(now);
      kick.stop(now + 0.15);

      // Drone Layers
      const layers = Math.max(1, Math.floor((this.currentConfig.density || 0.5) * 5));
      for (let i = 0; i < layers; i++) {
          const osc = this.audioContext.createOscillator();
          const g = this.audioContext.createGain();
          const f = this.audioContext.createBiquadFilter();
          const harmonic = (i % 3 === 0) ? 1 : (i % 3 === 1) ? 1.5 : 2; 
          osc.frequency.value = baseFreq * harmonic * (i + 1);
          osc.detune.value = (Math.random() - 0.5) * (this.currentConfig.temperature || 1) * 100;
          f.frequency.value = 200 + (this.currentConfig.brightness || 0.5) * 2000;
          g.gain.setValueAtTime(0, now);
          g.gain.linearRampToValueAtTime(0.05 / layers, now + duration * 0.2);
          g.gain.exponentialRampToValueAtTime(0.001, now + duration);
          osc.connect(f);
          f.connect(g);
          g.connect(this.gainNode);
          osc.start(now);
          osc.stop(now + duration + 0.1);
          this.activeNodes.push(osc, g, f);
      }

      // Emit simulation chunk to visualizer
      this.emit({
          type: 'chunk',
          chunk: {
              id: Math.random().toString(36),
              data: fakeEnvelope,
              startTime: now,
              duration: duration,
              receivedAt: Date.now()
          }
      });
  }

  public async play() {
    if (!this.session) return;
    if (this.audioContext?.state === 'suspended') await this.audioContext.resume();
    await this.session.play();
  }

  public async pause() {
    if (!this.session) return;
    await this.session.pause();
    this.stopSimulationLoop();
  }

  public async setPrompts(prompts: WeightedPrompt[]) {
    if (!this.session) return;
    const active = prompts.filter(p => p.isActive).map(p => ({ text: p.text, weight: p.weight }));
    if (active.length > 0) await this.session.setWeightedPrompts({ weightedPrompts: active });
  }

  public async updateConfig(config: MusicGenerationConfig) {
    if (!this.session) return;
    await this.session.setMusicGenerationConfig({ musicGenerationConfig: config });
  }

  public async resetContext() {
    if (!this.session) return;
    if (this.session.reset_context) {
      await this.session.reset_context();
    } else if (this.session.resetContext) {
      await this.session.resetContext();
    }
  }
}

export const musicService = new MusicService();

import React, { useEffect, useRef } from 'react';
import { musicService } from '../services/musicService';
import { VisualizerChunk, VisualizerEvent } from '../types';

interface VisualizerProps {
  isPlaying: boolean;
}

const Visualizer: React.FC<VisualizerProps> = ({ isPlaying }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationRef = useRef<number | null>(null);
  const chunksRef = useRef<VisualizerChunk[]>([]);

  useEffect(() => {
    // Subscribe to MusicService updates
    const unsubscribe = musicService.subscribe((event: VisualizerEvent) => {
      if (event.type === 'chunk' && event.chunk) {
        // Add new chunk to our list
        chunksRef.current.push(event.chunk);

        // Prune old chunks (older than 10 seconds ago to keep memory low)
        const now = musicService.getCurrentTime();
        chunksRef.current = chunksRef.current.filter(c => c.startTime + c.duration > now - 10);
      } else if (event.type === 'reset') {
        chunksRef.current = [];
      }
    });

    return () => unsubscribe();
  }, []);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const render = () => {
      const width = canvas.width;
      const height = canvas.height;
      const centerY = height / 2;
      const currentTime = musicService.getCurrentTime();

      ctx.clearRect(0, 0, width, height);

      // --- 1. Draw Playhead (Center Line) ---
      const playheadX = width / 2;
      ctx.strokeStyle = '#ff9cd6';
      ctx.lineWidth = 2;
      ctx.globalAlpha = 0.5;
      ctx.beginPath();
      ctx.moveTo(playheadX, 0);
      ctx.lineTo(playheadX, height);
      ctx.stroke();

      // --- 2. Render Chunks ---
      // Scale: How many pixels per second?
      const pixelsPerSecond = 100; 

      chunksRef.current.forEach(chunk => {
        // Check if chunk is visible
        // Chunk Start X = playheadX + (chunk.startTime - currentTime) * scale
        // If chunk is in the future, (startTime - currentTime) is positive -> to the right.
        // If chunk is past, negative -> to the left.

        const relativeStartSeconds = chunk.startTime - currentTime;
        const startX = playheadX + relativeStartSeconds * pixelsPerSecond;
        const endX = startX + chunk.duration * pixelsPerSecond;

        // Skip if completely off screen
        if (endX < 0 || startX > width) return;

        // Animation: Fade and Slide Down on entry
        const age = Date.now() - chunk.receivedAt;
        const animationDuration = 600; // ms
        let alpha = 1.0;
        let yOffset = 0;

        if (age < animationDuration) {
           const progress = age / animationDuration;
           // Ease out cubic
           const ease = 1 - Math.pow(1 - progress, 3);
           alpha = ease;
           yOffset = (1 - ease) * -30; // Slide from 30px above
        }

        ctx.globalAlpha = alpha;
        ctx.strokeStyle = '#e2e8f0';
        ctx.lineWidth = 1.5;
        ctx.beginPath();

        // Draw Envelope
        const envelope = chunk.data;
        const len = envelope.length / 2; // number of min/max pairs

        // Calculate step in pixels
        // total duration width = (chunk.duration * pixelsPerSecond)
        // points = len
        // pixels per point = width / len
        const chunkWidth = chunk.duration * pixelsPerSecond;
        const pixelStep = chunkWidth / len;

        for (let i = 0; i < len; i++) {
           const x = startX + i * pixelStep;
           // If x is outside, skip drawing this line for perf, but continue loop
           if (x < -5 || x > width + 5) continue;

           const min = envelope[i * 2];
           const max = envelope[i * 2 + 1];

           // Apply Y Offset from animation
           const yTop = centerY + min * (height * 0.4) + yOffset;
           const yBottom = centerY + max * (height * 0.4) + yOffset;

           ctx.moveTo(x, yTop);
           ctx.lineTo(x, yBottom);
        }
        ctx.stroke();
      });

      // Reset Alpha
      ctx.globalAlpha = 1.0;

      animationRef.current = requestAnimationFrame(render);
    };

    animationRef.current = requestAnimationFrame(render);

    return () => {
      if (animationRef.current !== null) cancelAnimationFrame(animationRef.current);
    };
  }, [isPlaying]);

  return (
    <canvas 
      ref={canvasRef} 
      width={1200} // High resolution width
      height={120} 
      className="w-full h-full"
    />
  );
};

